INSERT INTO messages (id, conversation_id, role, content, created_at) VALUES (75, 26, 'user', 'now add business definitions ', '2026-03-04 04:03:58.224714');
INSERT INTO messages (id, conversation_id, role, content, created_at) VALUES (76, 26, 'assistant', 'Here are the business definitions for all fields in the shipment dataset:

| Field Name | Business Term | Business Definition | Data Type | Example |
|---|---|---|---|---|
| shipment_id | Shipment Identifier | A unique system-generated identifier assigned to each shipment record. Serves as the primary key for the shipment entity and is used to reference the shipment across all related systems and documents. | VARCHAR(50) | SHP-2024-000123 |
| shipment_ref_no | Shipment Reference Number | A human-readable business reference number assigned to the shipment, typically generated by the logistics or ERP system. Used by business users and trading partners to track and communicate about a specific shipment. | VARCHAR(100) | REF-SA-2024-4521 |
| shipment_type | Shipment Type | Classifies the shipment as either an import or export transaction. Drives regulatory, customs, and documentation requirements applicable to the shipment. | VARCHAR(50) | Import, Export |
| shipment_date | Shipment Date | The official date on which the shipment was dispatched or handed over to the carrier. Used as the primary business date for reporting, SLA calculation, and regulatory compliance. | DATE | 2024-03-15 |
| shipment_status | Shipment Status | The current lifecycle status of the shipment, indicating its progress from creation through to final delivery. Valid values include: Draft, Booked, In Transit, Customs Hold, Delivered, Cancelled. | VARCHAR(50) | In Transit |
| origin_country_code | Origin Country Code | The ISO 3166-1 alpha-2 or alpha-3 country code representing the country from which the shipment originates. Used for trade statistics, regulatory reporting, and customs declarations. | VARCHAR(10) | SA, US, CN |
| destination_country_code | Destination Country Code | The ISO 3166-1 alpha-2 or alpha-3 country code representing the country to which the shipment is being sent. Used for import duty calculation, sanctions screening, and customs clearance. | VARCHAR(10) | AE, GB, DE |
| port_of_loading | Port of Loading | The name or UN/LOCODE of the port, airport, or terminal where the cargo is loaded onto the primary transport vessel or aircraft. Relevant for sea and air freight shipments. | VARCHAR(255) | Jeddah Islamic Port (SAJED) |
| port_of_discharge | Port of Discharge | The name or UN/LOCODE of the port, airport, or terminal where the cargo is unloaded from the primary transport vessel or aircraft. Used for freight cost calculation and customs entry. | VARCHAR(255) | Port of Rotterdam (NLRTM) |
| final_destination | Final Destination | The ultimate delivery address or location where the shipment is to be received by the consignee. May differ from the port of discharge when inland transport is involved. | VARCHAR(255) | Warehouse 5, Industrial Zone, Riyadh, Saudi Arabia |
| incoterm_code | Incoterm Code | The internationally recognized trade term (Incoterms 2020) that defines the responsibilities, costs, and risk transfer point between the seller and the buyer. Valid values: EXW, FCA, FOB, CIF, DAP, DDP, etc. | VARCHAR(10) | FOB, CIF, DDP |
| transport_mode | Transport Mode | The mode of transportation used for the primary leg of the shipment. Valid values: Sea, Air, Road, Rail, Multimodal. Determines applicable documentation requirements and carrier type. | VARCHAR(50) | Sea |
| carrier_name | Carrier Name | The full legal or commercial name of the transportation company (shipping line, airline, or trucking company) responsible for moving the cargo. Used for performance tracking and contract management. | VARCHAR(255) | Maersk Line, Saudi Airlines Cargo |
| vessel_flight_no | Vessel / Flight Number | The identifier of the vessel (ship name and voyage number) or flight number transporting the cargo. Used for tracking shipment movement and estimated arrival times. | VARCHAR(100) | MSC ANNA - VOY 245W, SV 8012 |
| bill_of_lading_no | Bill of Lading Number | The unique reference number of the Bill of Lading (B/L), which is the legal contract between the shipper and the ocean carrier. Serves as a title document for sea freight shipments. | VARCHAR(100) | MAEU123456789 |
| awb_no | Air Waybill Number | The unique reference number of the Air Waybill (AWB), which is the contract of carriage between the shipper and the airline for air freight shipments. Follows IATA format (3-digit airline code + 8 digits). | VARCHAR(100) | 176-12345678 |
| container_no | Container Number | The unique ISO 6346-compliant alphanumeric identifier assigned to the shipping container. Consists of a 4-letter owner code, 6-digit serial number, and 1 check digit. | VARCHAR(20) | MSCU1234567 |
| container_type | Container Type | The standardized classification of the shipping container based on its size and specification. Common values: 20GP (20-foot General Purpose), 40GP, 40HC (High Cube), 20RF (Reefer), 45HC. | VARCHAR(50) | 40HC, 20GP, 20RF |
| seal_no | Seal Number | The unique identifier of the security seal applied to the container door after loading. Used for tamper detection, customs verification, and cargo security compliance. | VARCHAR(100) | SL-9987654 |
| gross_weight_kg | Gross Weight (kg) | The total weight of the shipment including all goods, packaging, and container tare weight, expressed in kilograms. Used for freight cost calculation, vessel load planning, and customs declarations. Must be greater than zero. | DECIMAL(18,3) | 24500.500 |
| net_weight_kg | Net Weight (kg) | The weight of the goods only, excluding all packaging materials and container tare weight, expressed in kilograms. Used for customs duty assessment and trade statistics. Must be less than or equal to gross weight. | DECIMAL(18,3) | 22000.000 |
| volume_cbm | Volume (CBM) | The total volumetric measurement of the shipment in cubic meters (CBM). Used for freight rate calculation, especially for lightweight but bulky cargo under volumetric weight pricing. Must be greater than zero. | DECIMAL(18,3) | 35.750 |
| total_packages | Total Number of Packages | The total count of individual packages, cartons, pallets, or handling units included in the shipment. Used for cargo receipt verification and customs documentation. Must be a positive integer. | INTEGER | 120 |
| package_type | Package Type | The type of packaging unit used for the shipment. Common values: Carton, Pallet, Drum, Bag, Crate, Bundle, Roll. Used for handling instructions and cargo manifests. | VARCHAR(100) | Carton, Pallet, Drum |
| freight_currency | Freight Currency | The ISO 4217 three-letter currency code in which the freight charges are invoiced and paid. Used for financial reporting, FX conversion, and accounts payable processing. | VARCHAR(10) | USD, SAR, EUR |
| freight_amount | Freight Amount | The total cost of transportation services charged by the carrier for moving the shipment from origin to destination, expressed in the freight currency. Excludes insurance and ancillary charges. Must be a non-negative value. | DECIMAL(18,2) | 12500.00 |
| insurance_amount | Insurance Amount | The total premium paid for cargo insurance coverage during the shipment, expressed in the freight currency. Covers loss or damage to goods in transit. May be zero if no insurance was purchased. | DECIMAL(18,2) | 850.00 |
| created_by | Created By | The username or unique identifier of the system user who initially created the shipment record. Used for audit trail, accountability tracking, and access control review. | VARCHAR(100) | john.smith, USR-00452 |
| created_at | Created At | The system timestamp recording the exact date and time when the shipment record was first created in the system. Used for audit logging, SLA monitoring, and data lineage. Stored in UTC. | TIMESTAMP | 2024-03-10 08:45:23 |
| updated_at | Last Updated At | The system timestamp recording the most recent date and time when the shipment record was modified. Automatically updated by the system on every save operation. Used for change tracking and data freshness monitoring. Stored in UTC. | TIMESTAMP | 2024-03-15 14:22:10 |', '2026-03-04 04:04:36.890798');
