INSERT INTO messages (id, conversation_id, role, content, created_at) VALUES (118, 44, 'user', 'give me business defenitions for the attached excel sheet 

**Uploaded File: import_export_data_fields.xlsx**

**Sheet: shipment**
**Fields/Columns:** shipment_id, shipment_ref_no, shipment_type, shipment_date, shipment_status, origin_country_code, destination_country_code, port_of_loading, port_of_discharge, final_destination, incoterm_code, transport_mode, carrier_name, vessel_flight_no, bill_of_lading_no, awb_no, container_no, container_type, seal_no, gross_weight_kg, net_weight_kg, volume_cbm, total_packages, package_type, freight_currency, freight_amount, insurance_amount, created_by, created_at, updated_at

