INSERT INTO messages (id, conversation_id, role, content, created_at) VALUES (119, 44, 'assistant', 'Here are the business definitions for the fields in the **shipment** sheet:

| Field Name | Business Term | Business Definition | Data Type | Example |
|---|---|---|---|---|
| shipment_id | Shipment Identifier | A system-generated unique identifier assigned to each shipment record. Serves as the primary key for the shipment entity and is used to reference the shipment across all related systems and transactions. | INTEGER / UUID | 10001 |
| shipment_ref_no | Shipment Reference Number | A business-facing reference number assigned to the shipment, used for tracking and communication with carriers, customs authorities, and trading partners. May follow an organization-defined naming convention. | VARCHAR(50) | SHP-2024-00123 |
| shipment_type | Shipment Type | Classifies the shipment as either an import or export (and potentially re-export or transit). Determines the applicable regulatory framework, customs procedures, and documentation requirements under ZATCA customs regulations. | VARCHAR(20) | IMPORT, EXPORT, RE-EXPORT, TRANSIT |
| shipment_date | Shipment Date | The official date on which the shipment departed from the origin location or was handed over to the carrier. Used for customs declaration dating, duty calculation, and shipment timeline tracking. | DATE (YYYY-MM-DD) | 2024-03-15 |
| shipment_status | Shipment Status | Represents the current lifecycle stage of the shipment within the logistics and customs clearance process. Drives workflow decisions and tracking visibility for operations and compliance teams. | VARCHAR(30) | PENDING, IN_TRANSIT, CLEARED, DELIVERED, HELD |
| origin_country_code | Origin Country Code | The ISO 3166-1 alpha-2 or alpha-3 country code representing the country from which the shipment originates. Used for trade statistics, customs declarations, rules of origin determination, and tariff classification. | CHAR(2) or CHAR(3) | SA, CN, US, AE |
| destination_country_code | Destination Country Code | The ISO 3166-1 alpha-2 or alpha-3 country code representing the country to which the shipment is ultimately consigned. Used for export controls, trade compliance, and customs reporting. | CHAR(2) or CHAR(3) | SA, DE, GB, IN |
| port_of_loading | Port of Loading | The name or UN/LOCODE of the seaport, airport, or land border crossing where the shipment is loaded onto the primary transport vessel or vehicle. Recorded on the Bill of Lading or Air Waybill. | VARCHAR(100) | CNSHA (Shanghai), AEJEA (Jebel Ali) |
| port_of_discharge | Port of Discharge | The name or UN/LOCODE of the seaport, airport, or land crossing where the shipment is unloaded from the primary carrier. This is the first point of arrival in the destination country and is critical for customs entry. | VARCHAR(100) | SAJED (Jeddah Islamic Port), SADMM (King Abdulaziz Airport) |
| final_destination | Final Destination | The ultimate delivery location of the shipment beyond the port of discharge. This could be a warehouse, distribution center, or consignee address. Used for inland logistics planning and last-mile delivery. | VARCHAR(255) | Riyadh Industrial City, Warehouse 4, Al Nakheel District |
| incoterm_code | Incoterm Code | The standardized International Commercial Terms (Incoterms) code, as published by the International Chamber of Commerce (ICC), that defines the responsibilities of buyers and sellers for the delivery of goods, risk transfer, and cost allocation. | CHAR(3) | FOB, CIF, EXW, DDP, DAP |
| transport_mode | Transport Mode | The primary mode of transportation used to move the shipment from origin to destination. Determines the applicable customs documentation, inspection procedures, and regulatory requirements. | VARCHAR(20) | SEA, AIR, LAND, RAIL, MULTIMODAL |
| carrier_name | Carrier Name | The full legal or commercial name of the shipping company, airline, trucking company, or logistics provider responsible for transporting the shipment. Used for carrier performance tracking and customs declarations. | VARCHAR(255) | Saudi Airlines Cargo, CMA CGM, DHL Express |
| vessel_flight_no | Vessel / Flight Number | The unique identifier for the specific vessel voyage (for sea freight) or flight number (for air freight) carrying the shipment. Required for customs manifest matching and arrival notification tracking. | VARCHAR(50) | MSC MAYA V.2401, SV-802 |
| bill_of_lading_no | Bill of Lading Number | The unique reference number of the Bill of Lading (B/L), which is the legal contract between the shipper and the ocean carrier. Serves as a title document and receipt of goods for sea freight shipments. Null for non-sea shipments. | VARCHAR(50) | MEDUG1234567 |
| awb_no | Air Waybill Number | The unique reference number of the Air Waybill (AWB), which is the contract of carriage between the shipper and the airline for air freight shipments. Follows IATA 11-digit format. Null for non-air shipments. | VARCHAR(20) | 176-12345678 |
| container_no | Container Number | The unique identification number of the shipping container used to transport the goods, following the ISO 6346 standard format (4 letters + 7 digits). Null for non-containerized or air shipments. | CHAR(11) | MSCU1234567 |
| container_type | Container Type | Classifies the type and size of the shipping container used, based on ISO standards. Affects stowage planning, weight limits, and special handling requirements. | VARCHAR(20) | 20GP, 40GP, 40HC, 20RF, 45HC |
| seal_no | Seal Number | The unique identifier of the tamper-evident security seal applied to the container or cargo unit. Used by customs authorities and carriers to verify container integrity and detect unauthorized access during transit. | VARCHAR(50) | SL-2024-789456 |
| gross_weight_kg | Gross Weight (KG) | The total weight of the shipment including all goods, packaging materials, pallets, and the container tare weight, expressed in kilograms. Used for freight cost calculation, customs declaration, and transport compliance. | DECIMAL(12,3) | 15250.500 |
| net_weight_kg | Net Weight (KG) | The weight of the goods only, excluding all packaging materials, pallets, and container weight, expressed in kilograms. Used for customs duty calculation, statistical reporting, and product valuation purposes. | DECIMAL(12,3) | 12800.000 |
| volume_cbm | Volume (CBM) | The total volume of the shipment measured in cubic meters (CBM). Used for calculating volumetric freight charges and optimizing cargo space utilization. | DECIMAL(10,3) | 42.500 |
| total_packages | Total Number of Packages | The total count of individual packaging units (e.g., boxes, pallets, drums, crates) within the shipment. Declared on customs documents and the Bill of Lading for cargo verification purposes. | INTEGER | 120 |
| package_type | Package Type | Describes the type of physical packaging unit used for the shipment''s contents. Based on UN/CEFACT package type codes. Required for customs documentation and cargo handling instructions. | VARCHAR(50) | PALLET, CARTON, DRUM, CRATE, BAG |
| freight_currency | Freight Currency | The ISO 4217 three-letter currency code in which the freight charges are denominated and invoiced. Used for financial accounting, FX conversion, and cost reporting. | CHAR(3) | SAR, USD, EUR, AED |
| freight_amount | Freight Amount | The total monetary value of freight charges payable to the carrier for transporting the shipment, expressed in the freight currency. Used for cost accounting, customs valuation (CIF calculation), and financial reporting. | DECIMAL(18,2) | 12500.00 |
| insurance_amount | Insurance Amount | The monetary value of the cargo insurance premium or insured value associated with the shipment. Used in CIF (Cost, Insurance, Freight) valuation for customs duty assessment and financial risk management. | DECIMAL(18,2) | 3200.00 |
| created_by | Created By | The unique identifier or username of the system user or application that created the shipment record. Used for audit trail, data lineage, and accountability tracking. | VARCHAR(100) | usr_4521, system_api |
| created_at | Created At | The system-generated timestamp recording the exact date and time when the shipment record was first created in the system, stored in UTC. Used for audit logging, data lineage, and process timing analysis. | TIMESTAMP (UTC) | 2024-03-10T08:45:00Z |
| updated_at | Last Updated At | The system-generated timestamp recording the most recent date and time when any field in the shipment record was modified, stored in UTC. Used for change tracking, data freshness monitoring, and ETL incremental load processing. | TIMESTAMP (UTC) | 2024-03-15T14:22:00Z |', '2026-03-04 13:25:10.945195');
