INSERT INTO messages (id, conversation_id, role, content, created_at) VALUES (121, 45, 'assistant', 'Here are the business definitions for all fields in the **shipment** sheet:

| Field Name | Business Term | Business Definition | Data Type | Example |
|---|---|---|---|---|
| shipment_id | Shipment Identifier | A unique system-generated identifier assigned to each shipment record in the system. Serves as the primary key for the shipment entity and is used for internal referencing across all related tables. | INTEGER / BIGINT | 100001 |
| shipment_ref_no | Shipment Reference Number | A human-readable business reference number assigned to the shipment, used for communication with carriers, customers, and customs authorities. May follow a defined numbering convention such as SHP-YYYY-XXXXXX. | VARCHAR(50) | SHP-2024-000123 |
| shipment_type | Shipment Type | Classifies the nature of the shipment movement. Indicates whether goods are being imported into Saudi Arabia, exported out of Saudi Arabia, or in transit. Valid values typically include: IMPORT, EXPORT, TRANSIT, RE-EXPORT. | VARCHAR(20) | IMPORT |
| shipment_date | Shipment Date | The official date on which the shipment departed from its origin or was handed over to the carrier. Used as the primary business date for reporting, customs declarations, and SLA tracking. | DATE | 2024-03-15 |
| shipment_status | Shipment Status | Represents the current lifecycle stage of the shipment within the logistics and customs clearance process. Valid values may include: DRAFT, BOOKED, IN_TRANSIT, ARRIVED, CLEARED, DELIVERED, CANCELLED. | VARCHAR(30) | IN_TRANSIT |
| origin_country_code | Origin Country Code | The ISO 3166-1 alpha-2 or alpha-3 country code representing the country from which the shipment originated. Used for country-of-origin reporting and customs declarations. | VARCHAR(3) | SA, CN, US |
| destination_country_code | Destination Country Code | The ISO 3166-1 alpha-2 or alpha-3 country code representing the country to which the shipment is being delivered. Used for customs clearance and trade statistics reporting. | VARCHAR(3) | SA, DE, AE |
| port_of_loading | Port of Loading | The name or UN/LOCODE of the port, airport, or border crossing where the goods were loaded onto the primary carrier for international transport. Relevant for sea, air, and land shipments. | VARCHAR(100) | CNSHA (Shanghai), JEDDAH |
| port_of_discharge | Port of Discharge | The name or UN/LOCODE of the port, airport, or border crossing where the goods are offloaded from the primary international carrier upon arrival in the destination country. | VARCHAR(100) | SAJED (Jeddah Islamic Port) |
| final_destination | Final Destination | The ultimate delivery address or location where the goods will be delivered after customs clearance and any inland transportation. May differ from the port of discharge. | VARCHAR(255) | Riyadh Logistics Hub, King Khalid Industrial City |
| incoterm_code | Incoterm Code | The International Commercial Terms (Incoterms) code agreed upon between buyer and seller, defining the responsibilities for transportation, risk, insurance, and customs duties. Valid values follow ICC Incoterms 2020: EXW, FCA, CPT, CIP, DAP, DPU, DDP, FAS, FOB, CFR, CIF. | VARCHAR(3) | FOB, CIF, DAP |
| transport_mode | Transport Mode | The primary mode of transportation used to carry the shipment between origin and destination. Valid values include: SEA, AIR, LAND, RAIL, MULTIMODAL. Drives which transport-specific fields are applicable (e.g., AWB for air, B/L for sea). | VARCHAR(20) | SEA |
| carrier_name | Carrier Name | The legal or trade name of the shipping company, airline, or logistics provider responsible for transporting the goods. Used for carrier performance tracking and freight cost analysis. | VARCHAR(150) | Maersk Line, Saudi Airlines Cargo |
| vessel_flight_no | Vessel / Flight Number | The identifier of the vessel (ship name or IMO number) for sea shipments, or the flight number for air shipments. Used to track the physical transport unit carrying the goods. | VARCHAR(50) | MSC DIANA, SV-7041 |
| bill_of_lading_no | Bill of Lading Number | The unique reference number of the Bill of Lading (B/L), a legal document issued by the sea carrier confirming receipt of goods for shipment. Applicable only to sea freight shipments. Acts as a title document and contract of carriage. | VARCHAR(50) | MAEU123456789 |
| awb_no | Air Waybill Number | The unique reference number of the Air Waybill (AWB), a non-negotiable transport document issued by an airline or freight forwarder for air cargo shipments. Follows the IATA format: airline code (3 digits) + 8-digit serial number. | VARCHAR(20) | 176-12345678 |
| container_no | Container Number | The unique alphanumeric identifier assigned to a shipping container, following the ISO 6346 standard format (4-letter owner code + 6-digit serial number + check digit). Applicable to FCL and LCL sea freight shipments. | VARCHAR(15) | MSCU1234567 |
| container_type | Container Type | Specifies the ISO standard type and size of the shipping container used. Common values include: 20GP (20-foot General Purpose), 40GP (40-foot General Purpose), 40HC (40-foot High Cube), 20RF (20-foot Refrigerated), 45HC. | VARCHAR(10) | 40HC |
| seal_no | Container Seal Number | The unique identifier of the security seal affixed to the container door at the point of loading. Used by customs authorities to verify container integrity upon arrival. A broken or missing seal triggers inspection. | VARCHAR(50) | SEAL-9876543 |
| gross_weight_kg | Gross Weight (KG) | The total weight of the shipment including all goods, packaging, pallets, and dunnage, expressed in kilograms. Used for freight cost calculation, customs declarations, and weight-based compliance checks. Must be greater than or equal to net weight. | DECIMAL(12,3) | 15250.500 |
| net_weight_kg | Net Weight (KG) | The weight of the actual goods only, excluding all packaging materials, expressed in kilograms. Used for customs valuation, duty calculation, and statistical reporting. Must be less than or equal to gross weight. | DECIMAL(12,3) | 14000.000 |
| volume_cbm | Volume (CBM) | The total volume of the shipment expressed in cubic meters (CBM — Cubic Meters). Used for volumetric freight calculation and container capacity planning. | DECIMAL(10,3) | 32.500 |
| total_packages | Total Number of Packages | The total count of individual packages, cartons, pallets, or units that make up the shipment. Used in customs declarations and for physical count verification upon delivery. Must be a positive integer. | INTEGER | 250 |
| package_type | Package Type | Describes the type of packaging used for the shipment goods. Common values include: CARTON, PALLET, DRUM, CRATE, BAG, ROLL, BUNDLE, LOOSE. Used for handling instructions and customs documentation. | VARCHAR(30) | CARTON |
| freight_currency | Freight Currency | The ISO 4217 three-letter currency code in which the freight charges are denominated and invoiced. Used for financial reporting and foreign exchange conversion. | VARCHAR(3) | USD, SAR, EUR |
| freight_amount | Freight Amount | The total cost of freight charges agreed upon with the carrier for transporting the shipment, expressed in the currency specified in freight_currency. Used for cost allocation, profitability analysis, and customs valuation under CIF incoterms. | DECIMAL(18,2) | 12500.00 |
| insurance_amount | Insurance Amount | The value of the cargo insurance premium or insured amount for the shipment, expressed in the same or related currency as freight. Used for customs CIF valuation and risk management reporting. | DECIMAL(18,2) | 850.00 |
| created_by | Created By | The system username or user identifier of the individual who created the shipment record in the system. Used for audit trail, accountability, and data lineage tracking. | VARCHAR(100) | ahmed.ali, system_api |
| created_at | Record Creation Timestamp | The system-generated date and time when the shipment record was first created in the database. Used for audit purposes, SLA tracking, and data lineage. Should be automatically populated by the system and never manually editable. | TIMESTAMP | 2024-03-14 09:23:45 |
| updated_at | Record Last Update Timestamp | The system-generated date and time when the shipment record was most recently modified. Automatically updated on every record change. Used for change tracking, data synchronization, and audit trail purposes. Must always be greater than or equal to created_at. | TIMESTAMP | 2024-03-15 14:10:02 |', '2026-03-04 13:28:30.311286');
