INSERT INTO messages (id, conversation_id, role, content, created_at) VALUES (123, 46, 'assistant', 'Here is the data classification for each field in the **shipment** sheet, aligned with the Saudi SDAIA NDMO data classification framework.

| Field Name | Classification Level | Classification Rationale | Data Owner | Sensitivity Category |
|---|---|---|---|---|
| shipment_id | Restricted | Internal system identifier used to track shipments; not publicly available but not individually sensitive. | Customs Data Owner | Internal Identifier |
| shipment_ref_no | Restricted | Business reference number for the shipment; internal operational data that should not be publicly exposed. | Customs Data Owner | Internal Identifier |
| shipment_type | Public | General categorical value (e.g., Import/Export) that does not reveal sensitive business or personal information. | Customs Data Owner | Operational Metadata |
| shipment_date | Restricted | Date of shipment; when combined with other fields can reveal business patterns or trade activity timelines. | Customs Data Owner | Operational Metadata |
| shipment_status | Restricted | Internal workflow/process status; reveals operational state of a customs transaction. | Customs Data Owner | Operational Metadata |
| origin_country_code | Public | Standardized ISO country code indicating origin; publicly known and non-sensitive in isolation. | Customs Data Owner | Trade Reference Data |
| destination_country_code | Public | Standardized ISO country code indicating destination; publicly known and non-sensitive in isolation. | Customs Data Owner | Trade Reference Data |
| port_of_loading | Public | Name or code of the port where cargo is loaded; internationally published and non-sensitive in isolation. | Customs Data Owner | Trade Reference Data |
| port_of_discharge | Public | Name or code of the port where cargo is discharged; internationally published and non-sensitive in isolation. | Customs Data Owner | Trade Reference Data |
| final_destination | Restricted | Specific final delivery location; may reveal supply chain details or private business premises when combined with other fields. | Customs Data Owner | Logistics Detail |
| incoterm_code | Restricted | Standardized trade term (e.g., FOB, CIF); reveals contractual trade arrangements between commercial parties. | Customs Data Owner | Commercial Data |
| transport_mode | Public | Mode of transport (e.g., Sea, Air, Road); general categorical data with no inherent sensitivity. | Customs Data Owner | Operational Metadata |
| carrier_name | Restricted | Name of the logistics/shipping carrier; reveals business relationships and could be commercially sensitive. | Customs Data Owner | Commercial Data |
| vessel_flight_no | Restricted | Vessel name or flight number carrying the shipment; operational detail that can be used to track cargo movements. | Customs Data Owner | Logistics Detail |
| bill_of_lading_no | Confidential | Official shipping document number; a legally binding document reference that can be used to claim cargo and reveals commercial transaction details. | Customs Data Owner | Legal / Commercial Document |
| awb_no | Confidential | Air Waybill number; official air freight document reference tied to legal custody of goods and commercial transaction data. | Customs Data Owner | Legal / Commercial Document |
| container_no | Restricted | Unique container identifier; can be used to track physical cargo and is operationally sensitive. | Customs Data Owner | Logistics Detail |
| container_type | Public | Standardized container type code (e.g., 20GP, 40HC); generic reference data with no inherent sensitivity. | Customs Data Owner | Trade Reference Data |
| seal_no | Confidential | Customs or carrier seal number on a container; a security-critical identifier whose disclosure could enable tampering or customs fraud. | Customs Data Owner | Security / Integrity Data |
| gross_weight_kg | Restricted | Total weight of shipment including packaging; reveals cargo volume details that may be commercially sensitive. | Customs Data Owner | Commercial Data |
| net_weight_kg | Restricted | Weight of goods excluding packaging; directly tied to duties, tariff calculations, and commercial valuation. | Customs Data Owner | Commercial Data |
| volume_cbm | Restricted | Cubic measurement of the shipment; reveals freight sizing details used in commercial and duty calculations. | Customs Data Owner | Commercial Data |
| total_packages | Restricted | Number of packages in the shipment; operational detail that forms part of the cargo declaration record. | Customs Data Owner | Operational Metadata |
| package_type | Public | Type of packaging (e.g., Carton, Pallet); generic categorical data with no inherent sensitivity. | Customs Data Owner | Trade Reference Data |
| freight_currency | Restricted | Currency code used for freight billing; part of financial transaction context. | Finance Data Owner | Financial Data |
| freight_amount | Confidential | Monetary value paid for freight services; a financial figure that reveals commercial pricing arrangements and is subject to audit and regulatory review. | Finance Data Owner | Financial Data |
| insurance_amount | Confidential | Monetary value of cargo insurance; a financial figure directly linked to cargo valuation and commercial arrangements. | Finance Data Owner | Financial Data |
| created_by | Confidential | Username or employee ID of the person who created the record; constitutes personal data (PII) under Saudi PDPL linking an individual to a specific transaction. | HR / IAM Data Owner | Personal Data (PII) |
| created_at | Restricted | System timestamp of record creation; internal audit/operational metadata. | Customs Data Owner | Audit Metadata |
| updated_at | Restricted | System timestamp of the last record update; internal audit/operational metadata. | Customs Data Owner | Audit Metadata |', '2026-03-04 13:32:35.132199');
