INSERT INTO messages (id, conversation_id, role, content, created_at) VALUES (125, 47, 'assistant', 'Here is the data classification for each field in the **shipment** sheet, aligned with the Saudi SDAIA NDMO data classification framework.

| Field Name | Classification Level | Classification Rationale | Data Owner | Sensitivity Category |
|---|---|---|---|---|
| shipment_id | Restricted | Internal system-generated identifier used to track shipments; not publicly disclosed but not individually sensitive | Customs & Trade Operations | Internal Identifier |
| shipment_ref_no | Restricted | Business reference number used internally and shared with trade partners; could reveal operational patterns if disclosed broadly | Customs & Trade Operations | Internal Identifier |
| shipment_type | Public | General categorization of shipment (e.g., import/export); no harm if disclosed | Customs & Trade Operations | Operational Data |
| shipment_date | Restricted | Date of shipment; in aggregate could reveal trade volumes and patterns; limited harm individually | Customs & Trade Operations | Operational Data |
| shipment_status | Restricted | Internal workflow status; disclosure may reveal clearance or inspection decisions | Customs & Trade Operations | Operational Data |
| origin_country_code | Public | Country of origin is a standard trade field often required on public declarations and manifests | Customs & Trade Operations | Trade Data |
| destination_country_code | Public | Country of destination is a standard trade field disclosed on commercial invoices and manifests | Customs & Trade Operations | Trade Data |
| port_of_loading | Public | Port of loading is disclosed on public shipping documents such as bills of lading | Customs & Trade Operations | Trade Data |
| port_of_discharge | Public | Port of discharge is disclosed on public shipping documents; no harm if disclosed | Customs & Trade Operations | Trade Data |
| final_destination | Restricted | Final delivery address or location may reveal business premises or trading partner locations; limited internal use | Customs & Trade Operations | Operational Data |
| incoterm_code | Restricted | Incoterm (e.g., FOB, CIF) reflects commercial agreement terms; internal business context; minor harm if disclosed | Customs & Trade Operations | Commercial Data |
| transport_mode | Public | Mode of transport (air/sea/land) is a standard trade field with no sensitivity | Customs & Trade Operations | Trade Data |
| carrier_name | Restricted | Name of carrier (shipping line, airline); may be commercially sensitive and reveal preferred vendor relationships | Customs & Trade Operations | Commercial Data |
| vessel_flight_no | Restricted | Vessel or flight number links to specific transport movements; disclosure could raise security or operational concerns | Customs & Trade Operations | Operational Data |
| bill_of_lading_no | Confidential | A legal shipping document number that can be used to claim cargo; unauthorized disclosure could enable fraud or cargo theft | Customs & Trade Operations | Legal / Commercial Document |
| awb_no | Confidential | Air waybill number is a legally binding document reference; unauthorized disclosure could enable fraudulent cargo claims | Customs & Trade Operations | Legal / Commercial Document |
| container_no | Confidential | Container number is a trackable identifier; disclosure could enable unauthorized cargo tracking, tampering, or theft | Customs & Trade Operations | Security-Sensitive Identifier |
| container_type | Public | Standard ISO container type classification (e.g., 20GP, 40HC); no sensitivity | Customs & Trade Operations | Trade Data |
| seal_no | Confidential | Customs/security seal number is a physical security identifier; disclosure could facilitate seal duplication or tampering | Customs & Trade Operations | Security-Sensitive Identifier |
| gross_weight_kg | Restricted | Shipment weight data; in aggregate could reveal trade volumes; limited sensitivity individually | Customs & Trade Operations | Trade Data |
| net_weight_kg | Restricted | Net weight of goods; relevant to duty and tax calculation; limited sensitivity individually | Customs & Trade Operations | Trade Data |
| volume_cbm | Restricted | Cubic measurement of shipment; operational logistics data with minor sensitivity | Customs & Trade Operations | Operational Data |
| total_packages | Restricted | Count of packages in a shipment; operational data with minor sensitivity | Customs & Trade Operations | Operational Data |
| package_type | Public | Type of packaging (e.g., carton, pallet); standard trade descriptor with no sensitivity | Customs & Trade Operations | Trade Data |
| freight_currency | Restricted | Currency used for freight payment; reveals trade partner arrangements; minor sensitivity | Finance & Trade Operations | Financial Data |
| freight_amount | Confidential | Monetary value of freight charges; commercially sensitive financial data that could reveal pricing agreements and trade volumes | Finance & Trade Operations | Financial Data |
| insurance_amount | Confidential | Insurance value reflects the declared value of goods; commercially sensitive and relevant to duty/tax assessments | Finance & Trade Operations | Financial Data |
| created_by | Confidential | Username or employee ID of the record creator; constitutes employee PII and links individuals to operational actions | Data Governance / HR | Personal Data (PII) |
| created_at | Restricted | System timestamp of record creation; internal audit trail data with minor sensitivity | Data Governance / IT | Audit Data |
| updated_at | Restricted | System timestamp of last record update; internal audit trail data with minor sensitivity | Data Governance / IT | Audit Data |', '2026-03-04 13:47:09.763245');
INSERT INTO messages (id, conversation_id, role, content, created_at) VALUES (126, 47, 'user', 'give me the business defeintion ', '2026-03-04 13:47:59.587797');
INSERT INTO messages (id, conversation_id, role, content, created_at) VALUES (127, 47, 'assistant', 'Here are the business definitions for each field in the **shipment** sheet.

| Field Name | Business Term | Business Definition | Data Type | Example |
|---|---|---|---|---|
| shipment_id | Shipment Identifier | A unique system-generated identifier assigned to each shipment record upon creation. It serves as the primary key for the shipment entity and is used to reference the shipment across all internal systems and processes. | INTEGER / BIGINT | 100001 |
| shipment_ref_no | Shipment Reference Number | A human-readable business reference number assigned to a shipment for identification and tracking purposes across internal departments and external trade partners. May follow a structured naming convention (e.g., SHP-2024-00123). | VARCHAR(50) | SHP-2024-00123 |
| shipment_type | Shipment Type | Classifies the nature of the shipment in terms of trade direction. Valid values typically include IMPORT (goods entering the Kingdom), EXPORT (goods leaving the Kingdom), RE-EXPORT, and TRANSIT. Drives applicable regulatory and customs procedures. | VARCHAR(20) | IMPORT, EXPORT, RE-EXPORT, TRANSIT |
| shipment_date | Shipment Date | The official date on which the shipment was dispatched or registered for movement. Used for regulatory reporting, duty calculation timelines, and shipment lifecycle tracking. Must be a valid calendar date and should not be a future date for completed shipments. | DATE | 2024-03-15 |
| shipment_status | Shipment Status | Represents the current lifecycle stage of the shipment within the customs and logistics process. Valid values may include DRAFT, SUBMITTED, UNDER_INSPECTION, CLEARED, RELEASED, REJECTED, or CANCELLED. Governs workflow transitions and processing actions. | VARCHAR(30) | CLEARED |
| origin_country_code | Origin Country Code | The ISO 3166-1 alpha-2 or alpha-3 standard code representing the country from which the goods originated or were manufactured. Used for rules of origin determination, trade statistics, and regulatory compliance. | VARCHAR(3) | SA, US, CN |
| destination_country_code | Destination Country Code | The ISO 3166-1 alpha-2 or alpha-3 standard code representing the country to which the goods are being shipped. Used for export control, trade statistics, and determination of applicable agreements and restrictions. | VARCHAR(3) | AE, GB, DE |
| port_of_loading | Port of Loading | The name or code of the seaport, airport, or land border crossing where the goods were physically loaded onto the primary transport vehicle. Referenced in shipping documents such as the Bill of Lading. | VARCHAR(100) | Jeddah Islamic Port |
| port_of_discharge | Port of Discharge | The name or code of the seaport, airport, or land border crossing where the goods are scheduled to be unloaded from the primary transport vehicle. Referenced in shipping and customs documentation. | VARCHAR(100) | Dubai Port (Jebel Ali) |
| final_destination | Final Destination | The ultimate physical location or address where the goods will be delivered after customs clearance and any intermediate handling. May differ from the port of discharge when inland delivery is involved. | VARCHAR(255) | Riyadh Industrial City, KSA |
| incoterm_code | Incoterm Code | The International Commercial Terms (Incoterms) code agreed upon between the buyer and seller, defining the responsibilities for transportation costs, insurance, and risk transfer. Valid values follow ICC Incoterms 2020 (e.g., FOB, CIF, EXW, DAP, DDP). | VARCHAR(10) | FOB, CIF, EXW, DDP |
| transport_mode | Transport Mode | The primary mode of transportation used to carry the shipment from origin to destination. Valid values include SEA, AIR, LAND, RAIL, and MULTIMODAL. Determines applicable documentation requirements and customs procedures. | VARCHAR(20) | SEA |
| carrier_name | Carrier Name | The full legal or trade name of the transportation company (shipping line, airline, or trucking company) responsible for physically transporting the goods. Used for vendor management, liability tracking, and regulatory reporting. | VARCHAR(150) | Saudi Airlines Cargo |
| vessel_flight_no | Vessel / Flight Number | The official identifier of the vessel (ship name or IMO number) or flight number used to transport the goods. Used for transport tracking, port coordination, and customs arrival/departure manifests. | VARCHAR(50) | EK802, MSC DIANA |
| bill_of_lading_no | Bill of Lading Number | The unique reference number of the Bill of Lading (B/L), a legally binding document issued by the carrier acknowledging receipt of goods for shipment. Serves as a document of title and contract of carriage for sea freight. Applicable only when transport_mode = SEA. | VARCHAR(50) | MAEU123456789 |
| awb_no | Air Waybill Number | The unique reference number of the Air Waybill (AWB), a legally binding transport document issued by an airline or freight forwarder for air cargo shipments. Serves as a receipt, contract of carriage, and customs declaration reference. Applicable only when transport_mode = AIR. | VARCHAR(50) | 176-12345678 |
| container_no | Container Number | The unique ISO 6346-compliant alphanumeric identifier assigned to a shipping container. Follows the format: 4-letter owner code + 6-digit serial number + 1 check digit (e.g., MSCU1234567). Used for container tracking, port operations, and customs inspection. | VARCHAR(20) | MSCU1234567 |
| container_type | Container Type | The standardized ISO classification code describing the physical type and size of the shipping container used. Common values include 20GP (20-foot General Purpose), 40HC (40-foot High Cube), 20RF (Reefer), and 40OT (Open Top). | VARCHAR(10) | 20GP, 40HC, 20RF |
| seal_no | Seal Number | The unique identifier of the tamper-evident security seal affixed to the container or cargo by customs authorities or the carrier. Used to verify container integrity upon arrival and detect unauthorized access during transit. | VARCHAR(50) | CUS-2024-98765 |
| gross_weight_kg | Gross Weight (KG) | The total weight of the shipment including goods, packaging, and container tare weight, measured in kilograms. Used for freight cost calculation, transport capacity planning, and customs declarations. Must be a positive numeric value. | DECIMAL(18,3) | 15250.500 |
| net_weight_kg | Net Weight (KG) | The weight of the goods only, excluding all packaging materials and container weight, measured in kilograms. Used for duty and tax assessment, trade statistics, and regulatory reporting. Must be a positive numeric value less than or equal to gross_weight_kg. | DECIMAL(18,3) | 12000.000 |
| volume_cbm | Volume (CBM) | The total volume of the shipment measured in cubic meters (CBM). Used for freight cost calculation (volumetric weight), container capacity planning, and warehousing. Must be a positive numeric value. | DECIMAL(18,3) | 45.750 |
| total_packages | Total Packages | The total count of individual packages, cartons, pallets, or units included in the shipment. Used for cargo manifest verification, customs examination, and physical count reconciliation at port. Must be a positive integer. | INTEGER | 120 |
| package_type | Package Type | Describes the physical form or container type used to pack the goods. Common values include CARTON, PALLET, DRUM, CRATE, BAG, ROLL, and BUNDLE. Used for handling instructions and warehouse operations. | VARCHAR(50) | CARTON |
| freight_currency | Freight Currency | The ISO 4217 three-letter currency code in which the freight charges are denominated and paid (e.g., SAR, USD, EUR). Must correspond to a valid active currency code and be consistent with the freight_amount field. | VARCHAR(3) | SAR, USD, EUR |
| freight_amount | Freight Amount | The total monetary value of freight charges paid or agreed upon for transporting the shipment from origin to destination. Expressed in the currency specified in freight_currency. Used for cost accounting, landed cost calculation, and customs valuation. Must be a non-negative numeric value. | DECIMAL(18,2) | 12500.00 |
| insurance_amount | Insurance Amount | The monetary value of the cargo insurance premium or insured value declared for the shipment. Used in customs valuation (CIF calculation), risk management, and financial reporting. Must be a non-negative numeric value expressed in the same or specified currency. | DECIMAL(18,2) | 3200.00 |
| created_by | Created By | The username, employee ID, or system account identifier of the user or automated process that initially created the shipment record in the system. Used for audit trail, accountability tracking, and access control reviews. | VARCHAR(100) | ahmed.ali, SYS_IMPORT |
| created_at | Created At | The system-generated timestamp recording the exact date and time when the shipment record was first created in the database. Used for audit logging, SLA monitoring, and record lifecycle management. Must follow ISO 8601 format and cannot be null. | TIMESTAMP | 2024-03-15T09:30:00Z |
| updated_at | Updated At | The system-generated timestamp recording the most recent date and time when any field in the shipment record was modified. Automatically updated on every record change. Must be greater than or equal to created_at. Used for change tracking and data freshness monitoring. | TIMESTAMP | 2024-03-15T14:45:00Z |', '2026-03-04 13:48:41.293467');
