INSERT INTO messages (id, conversation_id, role, content, created_at) VALUES (146, 50, 'assistant', 'Here are the business definitions for the fields in the **shipment** sheet:

| Field Name | Business Term | Business Definition | Data Type | Example |
|---|---|---|---|---|
| shipment_id | Shipment Identifier | A unique system-generated identifier assigned to each shipment record. Serves as the primary key for the shipment entity and is used to reference the shipment across all related systems and processes. | INTEGER / BIGINT | 100001 |
| shipment_ref_no | Shipment Reference Number | A human-readable business reference number assigned to the shipment, used for tracking and communication purposes with carriers, customs authorities, and trading partners. May follow a defined organizational naming convention. | VARCHAR(50) | SHP-2024-00123 |
| shipment_type | Shipment Type | Classifies the shipment as either an import or export transaction. Determines the applicable customs procedures, duties, and regulatory requirements under ZATCA customs regulations. | VARCHAR(20) | IMPORT, EXPORT |
| shipment_date | Shipment Date | The official date on which the shipment was dispatched from the origin point or the date the shipment was formally initiated. Used for customs declarations, duty calculations, and transit time tracking. | DATE | 2024-03-15 |
| shipment_status | Shipment Status | Indicates the current lifecycle stage of the shipment within the logistics and customs clearance process. Used to track progress from initiation through final delivery. | VARCHAR(30) | PENDING, IN_TRANSIT, CLEARED, DELIVERED, CANCELLED |
| origin_country_code | Origin Country Code | The ISO 3166-1 alpha-2 or alpha-3 standard country code representing the country from which the shipment originates. Used in customs declarations and trade statistics reporting. | VARCHAR(3) | SA, AE, US, CN |
| destination_country_code | Destination Country Code | The ISO 3166-1 alpha-2 or alpha-3 standard country code representing the country to which the shipment is being sent. Used in customs declarations, duty assessment, and trade statistics. | VARCHAR(3) | SA, AE, US, GB |
| port_of_loading | Port of Loading | The name or code of the seaport, airport, or land border crossing where the shipment is loaded onto the primary carrier. Corresponds to the point of departure in the bill of lading or air waybill. | VARCHAR(100) | Jeddah Islamic Port, Dubai Port |
| port_of_discharge | Port of Discharge | The name or code of the seaport, airport, or land border crossing where the shipment is unloaded from the primary carrier. Typically corresponds to the arrival point stated in the transport document. | VARCHAR(100) | King Abdulaziz Port – Dammam |
| final_destination | Final Destination | The ultimate delivery location of the shipment beyond the port of discharge, such as a warehouse, distribution center, or customer address. May differ from the port of discharge when inland transport is involved. | VARCHAR(200) | Riyadh Central Warehouse, Zone 3 |
| incoterm_code | Incoterm Code | The internationally recognized trade term (as defined by ICC Incoterms® rules) that defines the responsibilities, costs, and risks between the buyer and seller for the shipment. Determines who bears freight, insurance, and customs costs. | VARCHAR(5) | EXW, FOB, CIF, DAP, DDP |
| transport_mode | Transport Mode | The primary mode of transportation used to carry the shipment from origin to destination. Determines applicable transport documents, regulations, and handling requirements. | VARCHAR(20) | SEA, AIR, LAND, MULTIMODAL |
| carrier_name | Carrier Name | The name of the shipping company, airline, or freight operator responsible for transporting the shipment. Used for tracking, liability, and freight payment purposes. | VARCHAR(150) | Saudi Airlines Cargo, MSC, DHL |
| vessel_flight_no | Vessel / Flight Number | The identifier of the specific vessel (ship name or IMO number) or flight number transporting the shipment. Used for tracking shipment movement and coordinating customs pre-arrival declarations. | VARCHAR(50) | MSC ANNA / SV 123 |
| bill_of_lading_no | Bill of Lading Number | The unique reference number of the Bill of Lading (B/L), a legally binding transport document issued by the carrier for sea freight shipments. Serves as a title of ownership, receipt of goods, and contract of carriage. | VARCHAR(50) | MSCU123456789 |
| awb_no | Air Waybill Number | The unique reference number of the Air Waybill (AWB), a transport document issued by the carrier for air freight shipments. Serves as a receipt of goods and non-negotiable contract of carriage for air transport. | VARCHAR(20) | 157-12345678 |
| container_no | Container Number | The internationally standardized unique identifier of the shipping container used to transport the goods, following the ISO 6346 format (4 letters + 7 digits). Used for tracking and customs examination. | VARCHAR(20) | MSCU1234567 |
| container_type | Container Type | Specifies the ISO standard size and type of the shipping container used (e.g., 20-foot standard, 40-foot high cube, refrigerated). Determines cargo capacity and handling requirements. | VARCHAR(20) | 20GP, 40GP, 40HC, 20RF |
| seal_no | Seal Number | The unique identifier of the security seal applied to the shipping container or cargo unit at the point of loading. Used by customs authorities to verify that the container has not been tampered with during transit. | VARCHAR(50) | SEAL-2024-98765 |
| gross_weight_kg | Gross Weight (KG) | The total weight of the shipment including all goods, packaging materials, and the container or pallet. Expressed in kilograms. Used for freight calculation, customs declaration, and transport compliance checks. | DECIMAL(18,3) | 15250.500 |
| net_weight_kg | Net Weight (KG) | The weight of the goods only, excluding all packaging materials and the container. Expressed in kilograms. Used in customs duty calculations, trade statistics, and product declarations. | DECIMAL(18,3) | 12000.000 |
| volume_cbm | Volume (CBM) | The total volumetric measurement of the shipment expressed in cubic meters (CBM). Used for freight rate calculation (when volume weight exceeds actual weight) and container space planning. | DECIMAL(18,3) | 35.750 |
| total_packages | Total Number of Packages | The total count of individual handling units (boxes, pallets, cartons, crates, etc.) that make up the shipment. Declared on customs and transport documents for verification during inspection. | INTEGER | 250 |
| package_type | Package Type | Describes the type of packaging used for the shipment''s goods, such as cartons, pallets, drums, or crates. Used for handling instructions and customs declaration purposes. | VARCHAR(50) | CARTON, PALLET, DRUM, CRATE |
| freight_currency | Freight Currency | The ISO 4217 three-letter currency code in which the freight charges are invoiced and paid. Used for financial reporting, duty valuation, and foreign exchange purposes. | VARCHAR(3) | SAR, USD, EUR |
| freight_amount | Freight Amount | The total cost of transporting the shipment from the port of loading to the port of discharge, expressed in the freight currency. May be included in the customs value calculation depending on the applicable incoterm. | DECIMAL(18,2) | 12500.00 |
| insurance_amount | Insurance Amount | The cost of cargo insurance covering the shipment against loss or damage during transit, expressed in the freight currency. May be included in the customs value (CIF valuation) per ZATCA customs regulations. | DECIMAL(18,2) | 875.00 |
| created_by | Created By | The username or system identifier of the user or automated process that initially created the shipment record in the system. Used for audit trail and data accountability purposes. | VARCHAR(100) | ahmed.ali / system_api |
| created_at | Created At | The system-generated timestamp recording the exact date and time when the shipment record was first created in the system. Used for audit trails, SLA monitoring, and chronological reporting. | TIMESTAMP | 2024-03-15 08:30:00 |
| updated_at | Last Updated At | The system-generated timestamp recording the most recent date and time when any field in the shipment record was modified. Automatically updated on every record change and used for change tracking and data synchronization. | TIMESTAMP | 2024-03-20 14:45:00 |', '2026-03-04 14:33:02.08495');
