          "rule_expression": "transport_mode IN (''SEA'',''AIR'',''ROAD'',''RAIL'',''MULTIMODAL'',''COURIER'')",
          "severity": "Critical",
          "expected_behavior": "Only standardized transport mode codes are stored.",
          "failure_example": "transport_mode = ''Ship'' or ''ocean''",
          "pass_example": "transport_mode = ''AIR''",
