          "rule_description": "vessel_flight_no should be populated for transport_mode = AIR (flight number) or SEA (vessel name) when status is BOOKED or beyond.",
          "rule_expression": "NOT (transport_mode IN (''AIR'',''SEA'') AND shipment_status NOT IN (''DRAFT'',''CANCELLED'') AND (vessel_flight_no IS NULL OR TRIM(vessel_flight_no) = ''''))",
          "severity": "High",
