          "rule_description": "container_no, when provided, must follow ISO 6346 format: 4 uppercase letters + 6 digits + 1 check digit (e.g., MSCU1234567).",
          "rule_expression": "container_no IS NULL OR container_no REGEXP ''^[A-Z]{4}[0-9]{7}$''",
          "severity": "High",
          "expected_behavior": "Container number is 11 characters: 4 letters + 7 digits.",
          "failure_example": "container_no = ''CONT-123456'' or ''MSC1234567''",
