    {
      "field_name": "gross_weight_kg",
      "inferred_data_type": "Numeric (Decimal)",
      "business_context": "Total gross weight of the shipment in kilograms including packaging. Used for freight calculation and customs.",
      "rules": [
        {
          "rule_id": "DQ-046",
          "rule_name": "Gross Weight Not Null",
          "rule_layer": "Technical",
          "dq_dimension": "Completeness",
          "rule_type": "Null Check",
          "rule_description": "gross_weight_kg must not be null for all active shipments.",
          "rule_expression": "gross_weight_kg IS NOT NULL",
          "severity": "Critical",
          "expected_behavior": "All shipments have a gross weight value.",
          "failure_example": "gross_weight_kg = NULL",
          "pass_example": "gross_weight_kg = 1250.50",
          "remediation": "Enforce NOT NULL; populate from manifest or weighbridge data."
        },
        {
          "rule_id": "DQ-047",
          "rule_name": "Gross Weight Numeric Type",
          "rule_layer": "Technical",
          "dq_dimension": "Validity",
          "rule_type": "Format",
          "rule_description": "gross_weight_kg must be a positive numeric value (decimal or integer).",
          "rule_expression": "gross_weight_kg REGEXP ''^[0-9]+(\\\\.[0-9]+)?$'' AND CAST(gross_weight_kg AS DECIMAL) > 0",
          "severity": "Critical",
          "expected_behavior": "Numeric decimal value greater than zero.",
          "failure_example": "gross_weight_kg = ''N/A'' or -50",
          "pass_example": "gross_weight_kg = 1250.50",
          "remediation": "Enforce numeric data type at column level; reject non-numeric input."
        },
        {
          "rule_id": "DQ-048",
          "rule_name": "Gross Weight Reasonable Range",
          "rule_layer": "Logical",
          "dq_dimension": "Accuracy",
          "rule_type": "Range",
          "rule_description": "gross_weight_kg must be > 0 and <= 500,000 kg (max for a single standard sea shipment). Values > 50,000 kg should be flagged for review.",
          "rule_expression": "gross_weight_kg > 0 AND gross_weight_kg <= 500000",
          "severity": "High",
          "expected_behavior": "Weight is a positive, plausible value for the shipment.",
          "failure_example": "gross_weight_kg = 0 or gross_weight_kg = 9999999",
          "pass_example": "gross_weight_kg = 18500.75",
          "remediation": "Flag extreme values for manual verification; check unit (ensure kg, not lbs or tonnes)."
        },
        {
          "rule_id": "DQ-049",
          "rule_name": "Gross Weight Precision",
          "rule_layer": "Technical",
          "dq_dimension": "Validity",
          "rule_type": "Format",
          "rule_description": "gross_weight_kg should have at most 3 decimal places of precision.",
          "rule_expression": "gross_weight_kg = ROUND(gross_weight_kg, 3)",
          "severity": "Low",
          "expected_behavior": "Weight is precise to at most 0.001 kg.",
          "failure_example": "gross_weight_kg = 1250.12345678",
          "pass_example": "gross_weight_kg = 1250.123",
          "remediation": "Round at ingestion to 3 decimal places."
        }
      ]
    },
    {
      "field_name": "net_weight_kg",
      "inferred_data_type": "Numeric (Decimal)",
      "business_context": "Net weight of goods only, excluding packaging. Used for customs duty calculation and customs declaration.",
