        {
          "rule_id": "DQ-050",
          "rule_name": "Net Weight Not Null",
          "rule_layer": "Technical",
          "dq_dimension": "Completeness",
          "rule_type": "Null Check",
          "rule_description": "net_weight_kg must not be null for active shipments.",
          "rule_expression": "net_weight_kg IS NOT NULL",
          "severity": "High",
          "expected_behavior": "All shipments have a net weight.",
          "failure_example": "net_weight_kg = NULL",
          "pass_example": "net_weight_kg = 1100.00",
          "remediation": "Enforce NOT NULL; derive from gross weight minus packaging weight if unavailable."
        },
        {
          "rule_id": "DQ-051",
          "rule_name": "Net Weight Numeric and Positive",
          "rule_layer": "Technical",
          "dq_dimension": "Validity",
          "rule_type": "Format",
          "rule_description": "net_weight_kg must be a positive numeric decimal value.",
          "rule_expression": "net_weight_kg REGEXP ''^[0-9]+(\\\\.[0-9]+)?$'' AND CAST(net_weight_kg AS DECIMAL) > 0",
          "severity": "Critical",
          "expected_behavior": "Positive decimal number.",
          "failure_example": "net_weight_kg = 0 or -10 or ''TBD''",
          "pass_example": "net_weight_kg = 1100.00",
          "remediation": "Reject non-numeric and zero/negative values at ingestion."
        },
        {
          "rule_id": "DQ-052",
          "rule_name": "Net Weight Less Than or Equal to Gross Weight",
          "rule_layer": "Logical",
          "dq_dimension": "Consistency",
          "rule_type": "Range",
          "rule_description": "net_weight_kg must always be less than or equal to gross_weight_kg (packaging cannot have negative weight).",
          "rule_expression": "net_weight_kg <= gross_weight_kg",
          "severity": "Critical",
          "expected_behavior": "Net weight is at most equal to gross weight.",
          "failure_example": "net_weight_kg = 1500, gross_weight_kg = 1200",
          "pass_example": "net_weight_kg = 1100, gross_weight_kg = 1250",
          "remediation": "Trigger validation at save; alert if net exceeds gross; verify with packing list."
        },
        {
          "rule_id": "DQ-053",
          "rule_name": "Net Weight Reasonable Range",
          "rule_layer": "Logical",
          "dq_dimension": "Accuracy",
          "rule_type": "Range",
          "rule_description": "net_weight_kg must be > 0 and <= 500,000 kg.",
          "rule_expression": "net_weight_kg > 0 AND net_weight_kg <= 500000",
          "severity": "High",
          "expected_behavior": "Plausible net weight within operational bounds.",
          "failure_example": "net_weight_kg = 600000",
          "pass_example": "net_weight_kg = 1100.50",
          "remediation": "Flag out-of-range values for review."
        }
      ]
    },
    {
