          "rule_description": "port_of_loading must be a valid UN/LOCODE. Saudi Customs FASAH portal and GAZT require standardized port codes for declaration accuracy.",
          "rule_expression": "port_of_loading IN (SELECT locode FROM ref_un_locodes WHERE active = TRUE)",
