          "rule_layer": "Business",
          "dq_dimension": "Consistency",
          "rule_type": "Cross-Field",
          "rule_description": "The country prefix of port_of_loading (first 2 chars of UN/LOCODE) should match origin_country_code. Mismatches indicate data entry errors or transshipment scenarios that must be explicitly documented.",
          "rule_expression": "LEFT(port_of_loading, 2) = origin_country_code OR transshipment_flag = TRUE",
