    {
      "field_name": "incoterm_code",
      "inferred_data_type": "String (Incoterms 2020 enum)",
      "business_context": "Incoterms define responsibility allocation between buyer and seller for shipping costs, risk, and insurance. Critical for freight_amount and insurance_amount validation, and ZATCA invoice accuracy.",
      "rules": [
        {
          "rule_id": "BL-023",
          "rule_name": "Incoterm Code Allowed Values (Incoterms 2020)",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Conditional",
          "rule_description": "incoterm_code must be one of the 11 Incoterms 2020 codes: EXW, FCA, CPT, CIP, DAP, DPU, DDP, FAS, FOB, CFR, CIF.",
          "rule_expression": "incoterm_code IN (''EXW'',''FCA'',''CPT'',''CIP'',''DAP'',''DPU'',''DDP'',''FAS'',''FOB'',''CFR'',''CIF'')",
          "severity": "Critical",
          "expected_behavior": "Only Incoterms 2020 codes are accepted.",
          "failure_example": "''DDU'' (obsolete Incoterms 2010 code) or ''Ex-Works'' (full name).",
          "pass_example": "''CIF'', ''FOB'', ''DAP''",
          "remediation": "Replace free text with Incoterms 2020 controlled dropdown. Reject obsolete Incoterms 2010 codes with migration mapping."
        },
        {
          "rule_id": "BL-024",
          "rule_name": "CIF/CIP Requires Insurance Amount",
          "rule_layer": "Business",
          "dq_dimension": "Completeness",
          "rule_type": "Conditional",
          "rule_description": "Under Incoterms 2020, CIF and CIP require the seller to obtain minimum insurance. Therefore, if incoterm_code IN (''CIF'',''CIP''), insurance_amount must be populated and > 0.",
          "rule_expression": "IF incoterm_code IN (''CIF'',''CIP'') THEN insurance_amount IS NOT NULL AND insurance_amount > 0",
          "severity": "Critical",
          "expected_behavior": "CIF/CIP shipments always have an insurance_amount recorded.",
          "failure_example": "incoterm_code = ''CIF'', insurance_amount = NULL.",
          "pass_example": "incoterm_code = ''CIF'', insurance_amount = 1500.00.",
          "remediation": "Make insurance_amount conditionally required in UI when incoterm is CIF or CIP. Add DB-level CHECK."
        },
        {
          "rule_id": "BL-025",
          "rule_name": "DDP Incoterm ZATCA Import VAT Handling",
          "rule_layer": "Business",
          "dq_dimension": "Compliance",
          "rule_type": "Conditional",
          "rule_description": "Under DDP (Delivered Duty Paid), the seller pays all import duties and VAT. ZATCA requires that the e-invoice for DDP shipments to Saudi Arabia include the 15% VAT amount paid by the seller. System must flag DDP IMPORT shipments for VAT-inclusive invoice generation.",
          "rule_expression": "IF incoterm_code = ''DDP'' AND shipment_type = ''IMPORT'' AND destination_country_code = ''SA'' THEN invoice_vat_inclusive = TRUE AND vat_rate = 0.15",
          "severity": "Critical",
          "expected_behavior": "DDP import invoices to Saudi Arabia are VAT-inclusive at 15%.",
          "failure_example": "DDP import to SA generates zero-rated invoice, causing ZATCA audit failure.",
          "pass_example": "DDP IMPORT to SA → invoice shows 15% VAT paid by seller.",
          "remediation": "Add DDP+IMPORT+SA condition in FATOORAH invoice generation logic. Flag records for tax team review."
        }
      ]
    },
    {
