          "remediation": "Add CHECK constraint gross_weight_kg > 0. Validate in UI before save."
        },
        {
          "rule_id": "BL-040",
          "rule_name": "Gross Weight Plausibility Threshold",
          "rule_layer": "Business",
          "dq_dimension": "Accuracy",
          "rule_type": "Conditional",
          "rule_description": "gross_weight_kg must not exceed the maximum payload capacity for the transport mode. SEA 20GP max ~28,000 kg; 40GP ~26,500 kg; AIR (depends on aircraft, flag values > 100,000 kg as suspect).",
          "rule_expression": "IF transport_mode = ''AIR'' THEN gross_weight_kg <= 100000 ELIF transport_mode = ''SEA'' AND container_type = ''20GP'' THEN gross_weight_kg <= 28000",
          "severity": "High",
          "expected_behavior": "Gross weight does not exceed transport mode''s physical maximum.",
          "failure_example": "transport_mode = ''AIR'', gross_weight_kg = 500000.",
          "pass_example": "transport_mode = ''AIR'', gross_weight_kg = 5000.",
