        }
      ]
    },
    {
      "field_name": "net_weight_kg",
      "inferred_data_type": "Decimal (positive numeric)",
      "business_context": "Net weight of goods excluding packaging. Used in customs valuation, duty calculation, and product-specific regulations (e.g., food, chemicals).",
      "rules": [
        {
          "rule_id": "BL-041",
          "rule_name": "Net Weight Must Be Positive",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Conditional",
          "rule_description": "net_weight_kg must be greater than zero.",
          "rule_expression": "net_weight_kg > 0",
          "severity": "Critical",
          "expected_behavior": "Net weight is always a positive non-zero value.",
          "failure_example": "net_weight_kg = 0.",
          "pass_example": "net_weight_kg = 1000.00.",
          "remediation": "Add CHECK constraint net_weight_kg > 0."
