        }
      ]
    },
    {
      "field_name": "volume_cbm",
      "inferred_data_type": "Decimal (positive numeric)",
      "business_context": "Volume of the shipment in cubic meters. Used in freight rate calculation (volumetric weight) and container/space utilization.",
      "rules": [
        {
          "rule_id": "BL-043",
          "rule_name": "Volume Must Be Positive",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Conditional",
          "rule_description": "volume_cbm must be greater than zero for all shipments.",
          "rule_expression": "volume_cbm > 0",
          "severity": "High",
          "expected_behavior": "Volume is always a positive non-zero value.",
          "failure_example": "volume_cbm = 0.",
          "pass_example": "volume_cbm = 12.5.",
          "remediation": "Add CHECK constraint volume_cbm > 0."
        },
        {
          "rule_id": "BL-044",
          "rule_name": "Volumetric Weight vs Actual Weight Comparison for Freight",
          "rule_layer": "Business",
          "dq_dimension": "Accuracy",
          "rule_type": "Cross-Field",
          "rule_description": "For AIR shipments, chargeable weight is max(gross_weight_kg, volume_cbm * 167). The system must compute and store chargeable weight for freight invoice reconciliation. A missing or inconsistent chargeable weight leads to billing disputes.",
          "rule_expression": "IF transport_mode = ''AIR'' THEN chargeable_weight_kg = GREATEST(gross_weight_kg, volume_cbm * 167)",
          "severity": "Medium",
          "expected_behavior": "Chargeable weight is correctly derived and stored for air shipments.",
