          "rule_id": "BL-013",
          "rule_name": "Sanctioned Country Alert for Origin",
          "rule_layer": "Business",
          "dq_dimension": "Accuracy",
          "rule_type": "Referential",
          "rule_description": "origin_country_code must be checked against the Saudi Arabia sanctioned/restricted countries list. Imports from certain countries may be prohibited or require special licensing.",
          "rule_expression": "origin_country_code NOT IN (SELECT country_code FROM ref_restricted_countries WHERE restriction_type = ''IMPORT_PROHIBITED'')",
          "severity": "Critical",
          "expected_behavior": "No shipments from prohibited origin countries without special authorization.",
          "failure_example": "origin_country_code from a country with active Saudi import prohibition.",
          "pass_example": "origin_country_code = ''CN'' — no active prohibition.",
          "remediation": "Integrate with ZATCA/Saudi Customs restricted country list; block or escalate to compliance team."
        }
      ]
    },
    {
      "field_name": "destination_country_code",
      "inferred_data_type": "String (ISO 3166-1 Alpha-2)",
      "business_context": "Destination country for the shipment. Determines export licensing requirements, ZATCA zero-rating eligibility, and re-export rules.",
      "rules": [
        {
          "rule_id": "BL-014",
          "rule_name": "Destination Country Code Must Be Valid ISO 3166-1 Alpha-2",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Referential",
          "rule_description": "destination_country_code must match a valid ISO 3166-1 Alpha-2 country code.",
          "rule_expression": "destination_country_code IN (SELECT country_code FROM ref_iso_countries)",
          "severity": "Critical",
          "expected_behavior": "Valid 2-character ISO country code stored.",
          "failure_example": "destination_country_code = ''UAE'' (should be ''AE'').",
          "pass_example": "destination_country_code = ''AE''.",
          "remediation": "Enforce FK to ref_iso_countries; use dropdown in UI."
        },
        {
          "rule_id": "BL-015",
          "rule_name": "Export License Required for Controlled Destination Countries",
          "rule_layer": "Business",
          "dq_dimension": "Completeness",
          "rule_type": "Conditional",
          "rule_description": "If destination_country_code is in a list of countries requiring export licenses under Saudi export control regulations, an export license number must be recorded.",
          "rule_expression": "IF destination_country_code IN (SELECT country_code FROM ref_export_controlled_countries) THEN export_license_no IS NOT NULL",
          "severity": "High",
          "expected_behavior": "Exports to controlled destinations are always accompanied by a license number.",
          "failure_example": "Shipment to a controlled country with no export_license_no recorded.",
          "pass_example": "destination_country_code = ''IR'' flagged; compliance team assigns license before shipment proceeds.",
          "remediation": "Add export_license_no field; integrate with Saudi SAGIA/Ministry of Commerce export license registry."
        }
      ]
    },
    {
      "field_name": "port_of_loading",
      "inferred_data_type": "String (UN/LOCODE)",
      "business_context": "Port where goods are loaded onto the vessel/aircraft. Must align with transport mode and origin country. Used in Bill of Lading and ZATCA customs declarations.",
      "rules": [
        {
          "rule_id": "BL-016",
          "rule_name": "Port of Loading Must Be Valid UN/LOCODE",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Referential",
          "rule_description": "port_of_loading must match a valid UN/LOCODE in the reference table for legitimate customs and freight documentation.",
          "rule_expression": "port_of_loading IN (SELECT locode FROM ref_un_locodes WHERE is_active = TRUE)",
          "severity": "High",
          "expected_behavior": "Only recognized port/airport codes are used.",
          "failure_example": "port_of_loading = ''Jeddah'' (free text) instead of ''SAJED''.",
          "pass_example": "port_of_loading = ''SAJED'' (Jeddah, Saudi Arabia).",
          "remediation": "Populate ref_un_locodes from UN/LOCODE dataset; enforce FK or validated lookup."
        },
        {
          "rule_id": "BL-017",
          "rule_name": "Port of Loading Must Match Origin Country",
          "rule_layer": "Business",
          "dq_dimension": "Consistency",
          "rule_type": "Cross-Field",
          "rule_description": "The country portion of port_of_loading (first 2 chars of UN/LOCODE) must match origin_country_code, unless the shipment is a transit/transhipment scenario.",
          "rule_expression": "IF shipment_type NOT IN (''TRANSIT'',''RE-EXPORT'') THEN LEFT(port_of_loading, 2) = origin_country_code",
          "severity": "High",
          "expected_behavior": "Port of loading country aligns with origin country for direct shipments.",
          "failure_example": "origin_country_code = ''CN'', port_of_loading = ''SAJED'' (Saudi Arabia).",
          "pass_example": "origin_country_code = ''CN'', port_of_loading = ''CNSHA'' (Shanghai).",
          "remediation": "Add cross-field validation at booking stage; allow override with transit flag and justification."
        }
      ]
    },
    {
      "field_name": "port_of_discharge",
      "inferred_data_type": "String (UN/LOCODE)",
      "business_context": "Port where goods are unloaded. For Saudi imports, this is typically Jeddah Islamic Port, King Abdulaziz Port Dammam, or King Khalid Airport. Used in customs entry documentation.",
      "rules": [
        {
          "rule_id": "BL-018",
          "rule_name": "Port of Discharge Must Be Valid UN/LOCODE",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Referential",
          "rule_description": "port_of_discharge must reference a valid UN/LOCODE.",
          "rule_expression": "port_of_discharge IN (SELECT locode FROM ref_un_locodes WHERE is_active = TRUE)",
          "severity": "High",
          "expected_behavior": "Valid port code used for discharge.",
          "failure_example": "port_of_discharge = ''Dammam port''.",
          "pass_example": "port_of_discharge = ''SADMM''.",
          "remediation": "Enforce lookup validation; same ref_un_locodes table as port_of_loading."
        },
        {
          "rule_id": "BL-019",
          "rule_name": "Port of Discharge Must Match Destination Country for Imports",
          "rule_layer": "Business",
          "dq_dimension": "Consistency",
          "rule_type": "Cross-Field",
          "rule_description": "For IMPORT shipments, the country code in port_of_discharge must match destination_country_code.",
          "rule_expression": "IF shipment_type = ''IMPORT'' THEN LEFT(port_of_discharge, 2) = destination_country_code",
          "severity": "High",
          "expected_behavior": "Imports discharge at a port in the destination country.",
          "failure_example": "destination_country_code = ''SA'', port_of_discharge = ''AEJEA'' (Jebel Ali, UAE).",
          "pass_example": "destination_country_code = ''SA'', port_of_discharge = ''SAJED''.",
          "remediation": "Cross-field validation at booking; alert if mismatch detected."
        }
      ]
    },
    {
      "field_name": "final_destination",
      "inferred_data_type": "String (free text or city/address)",
      "business_context": "The ultimate delivery location beyond the port of discharge. Required for customs for transit and multimodal shipments, and for inland transport SLA tracking.",
      "rules": [
        {
          "rule_id": "BL-020",
          "rule_name": "Final Destination Required for Transit Shipments",
          "rule_layer": "Business",
          "dq_dimension": "Completeness",
          "rule_type": "Conditional",
          "rule_description": "For TRANSIT and RE-EXPORT shipments, final_destination is mandatory as Saudi Customs requires the ultimate destination for transit bond calculations.",
          "rule_expression": "IF shipment_type IN (''TRANSIT'',''RE-EXPORT'') THEN final_destination IS NOT NULL AND TRIM(final_destination) != ''''",
          "severity": "Critical",
          "expected_behavior": "Transit/re-export records always have a documented final destination.",
          "failure_example": "shipment_type = ''TRANSIT'', final_destination = NULL.",
          "pass_example": "shipment_type = ''TRANSIT'', final_destination = ''Amman, Jordan''.",
          "remediation": "Make final_destination mandatory in UI for transit/re-export flow."
        }
      ]
    },
    {
      "field_name": "incoterm_code",
      "inferred_data_type": "String/Enum (ICC Incoterms 2020)",
      "business_context": "International Commercial Terms defining responsibility split for freight, insurance, and risk between buyer/seller. Affects ZATCA customs value calculation (CIF vs FOB) and freight invoice validation.",
      "rules": [
        {
          "rule_id": "BL-021",
          "rule_name": "Incoterm Code Must Be Valid ICC Incoterms 2020",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Referential",
          "rule_description": "incoterm_code must be one of the 11 valid Incoterms 2020 codes as published by the International Chamber of Commerce.",
          "rule_expression": "incoterm_code IN (''EXW'',''FCA'',''CPT'',''CIP'',''DAP'',''DPU'',''DDP'',''FAS'',''FOB'',''CFR'',''CIF'')",
          "severity": "Critical",
          "expected_behavior": "Only recognized Incoterm codes stored.",
          "failure_example": "incoterm_code = ''DDU'' (discontinued Incoterm from 2010 version).",
          "pass_example": "incoterm_code = ''CIF''.",
          "remediation": "Update to Incoterms 2020; populate from reference table; warn if legacy codes detected."
        },
        {
          "rule_id": "BL-022",
          "rule_name": "CIF Incoterm Requires Insurance Amount",
          "rule_layer": "Business",
          "dq_dimension": "Completeness",
          "rule_type": "Conditional",
          "rule_description": "Under CIF and CIP Incoterms, the seller must provide insurance. Therefore insurance_amount must be populated and > 0 when incoterm_code = ''CIF'' or ''CIP''.",
          "rule_expression": "IF incoterm_code IN (''CIF'',''CIP'') THEN insurance_amount IS NOT NULL AND insurance_amount > 0",
          "severity": "High",
          "expected_behavior": "CIF/CIP shipments always have an insurance amount recorded.",
          "failure_example": "incoterm_code = ''CIF'', insurance_amount = NULL.",
          "pass_example": "incoterm_code = ''CIF'', insurance_amount = 5000.00.",
          "remediation": "Enforce conditional mandatory field in application logic; alert operations on missing insurance."
        },
        {
          "rule_id": "BL-023",
          "rule_name": "Sea-Only Incoterms Not Applicable for Air Transport",
          "rule_layer": "Business",
          "dq_dimension": "Consistency",
          "rule_type": "Cross-Field",
          "rule_description": "Incoterms FAS, FOB, CFR, CIF are only valid for sea or inland waterway transport (ICC rule). If transport_mode = ''AIR'', these codes must not be used.",
          "rule_expression": "IF transport_mode = ''AIR'' THEN incoterm_code NOT IN (''FAS'',''FOB'',''CFR'',''CIF'')",
          "severity": "High",
          "expected_behavior": "Air shipments use multimodal Incoterms (EXW, FCA, CPT, CIP, DAP, DPU, DDP).",
          "failure_example": "transport_mode = ''AIR'', incoterm_code = ''FOB''.",
          "pass_example": "transport_mode = ''AIR'', incoterm_code = ''FCA''.",
          "remediation": "Add cross-field validation at booking; display warning and suggest correct Incoterm."
        }
      ]
    },
    {
      "field_name": "transport_mode",
      "inferred_data_type": "String/Enum",
      "business_context": "Mode of transport determining which carrier documents apply (Bill of Lading for sea, AWB for air, CMR for road). Affects Saudi Customs declaration type selection.",
      "rules": [
        {
          "rule_id": "BL-024",
          "rule_name": "Transport Mode Must Be From Approved List",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Referential",
          "rule_description": "transport_mode must be one of: SEA, AIR, ROAD, RAIL, MULTIMODAL, COURIER. These map to Saudi Customs declaration codes.",
          "rule_expression": "transport_mode IN (''SEA'',''AIR'',''ROAD'',''RAIL'',''MULTIMODAL'',''COURIER'')",
          "severity": "Critical",
          "expected_behavior": "Only approved transport modes stored.",
          "failure_example": "transport_mode = ''Ship'' or ''ocean''.",
          "pass_example": "transport_mode = ''SEA''.",
          "remediation": "Apply CHECK constraint or FK to ref_transport_modes."
        },
        {
          "rule_id": "BL-025",
          "rule_name": "Transport Mode Must Be Non-Null for Non-Draft Shipments",
          "rule_layer": "Business",
          "dq_dimension": "Completeness",
          "rule_type": "Conditional",
          "rule_description": "All non-DRAFT shipments must have a transport_mode to enable correct customs declaration selection.",
          "rule_expression": "IF shipment_status != ''DRAFT'' THEN transport_mode IS NOT NULL",
          "severity": "Critical",
          "expected_behavior": "All active shipments specify a transport mode.",
          "failure_example": "shipment_status = ''BOOKED'', transport_mode = NULL.",
          "pass_example": "shipment_status = ''BOOKED'', transport_mode = ''AIR''.",
          "remediation": "Block confirmation/booking without transport mode selection."
        }
      ]
    },
    {
      "field_name": "carrier_name",
      "inferred_data_type": "String (free text or SCAC/IATA code)",
      "business_context": "Name of the carrier (shipping line, airline, trucking company). Required for Saudi Customs manifest matching and claims processing.",
      "rules": [
        {
          "rule_id": "BL-026",
          "rule_name": "Carrier Name Required for Booked and Beyond Statuses",
          "rule_layer": "Business",
          "dq_dimension": "Completeness",
          "rule_type": "Conditional",
          "rule_description": "Once a shipment moves to BOOKED status, the carrier must be assigned.",
          "rule_expression": "IF shipment_status IN (''BOOKED'',''IN_TRANSIT'',''ARRIVED'',''UNDER_CUSTOMS_CLEARANCE'',''CLEARED'',''DELIVERED'',''COMPLETED'') THEN carrier_name IS NOT NULL AND TRIM(carrier_name) != ''''",
          "severity": "High",
          "expected_behavior": "Booked+ shipments always have a carrier name.",
          "failure_example": "shipment_status = ''IN_TRANSIT'', carrier_name = NULL.",
          "pass_example": "shipment_status = ''IN_TRANSIT'', carrier_name = ''Maersk Line''.",
          "remediation": "Make carrier_name mandatory on booking confirmation form; link to ref_carriers table."
        }
      ]
    },
    {
      "field_name": "vessel_flight_no",
      "inferred_data_type": "String",
      "business_context": "Vessel name/voyage number (for sea) or flight number (for air). Mandatory on customs manifests for Saudi Customs clearance.",
      "rules": [
        {
          "rule_id": "BL-027",
          "rule_name": "Vessel/Flight Number Required for Sea and Air Shipments",
          "rule_layer": "Business",
          "dq_dimension": "Completeness",
          "rule_type": "Conditional",
          "rule_description": "For SEA and AIR transport modes, vessel_flight_no must be populated when the shipment reaches IN_TRANSIT status, as it appears on customs manifests.",
          "rule_expression": "IF transport_mode IN (''SEA'',''AIR'') AND shipment_status IN (''IN_TRANSIT'',''ARRIVED'',''UNDER_CUSTOMS_CLEARANCE'',''CLEARED'',''DELIVERED'',''COMPLETED'') THEN vessel_flight_no IS NOT NULL",
          "severity": "High",
          "expected_behavior": "Sea/air shipments in transit have vessel/flight number.",
          "failure_example": "transport_mode = ''SEA'', shipment_status = ''IN_TRANSIT'', vessel_flight_no = NULL.",
          "pass_example": "transport_mode = ''AIR'', vessel_flight_no = ''SV2345''.",
          "remediation": "Require vessel/flight number before allowing IN_TRANSIT status for sea/air modes."
        }
      ]
    },
    {
      "field_name": "bill_of_lading_no",
      "inferred_data_type": "String",
      "business_context": "Original Bill of Lading number — the key document of title for sea freight. Required for Saudi Customs clearance and cargo release.",
      "rules": [
        {
          "rule_id": "BL-028",
          "rule_name": "Bill of Lading Required for Sea Freight Shipments",
          "rule_layer": "Business",
          "dq_dimension": "Completeness",
          "rule_type": "Conditional",
          "rule_description": "For transport_mode = ''SEA'', bill_of_lading_no must be populated at ARRIVED status or before customs clearance can proceed.",
          "rule_expression": "IF transport_mode = ''SEA'' AND shipment_status IN (''ARRIVED'',''UNDER_CUSTOMS_CLEARANCE'',''CLEARED'') THEN bill_of_lading_no IS NOT NULL AND TRIM(bill_of_lading_no) != ''''",
          "severity": "Critical",
          "expected_behavior": "All sea freight shipments under clearance have a B/L number.",
          "failure_example": "transport_mode = ''SEA'', shipment_status = ''UNDER_CUSTOMS_CLEARANCE'', bill_of_lading_no = NULL.",
          "pass_example": "transport_mode = ''SEA'', bill_of_lading_no = ''MAEU123456789''.",
          "remediation": "Block customs clearance initiation for sea shipments without B/L number."
        },
        {
          "rule_id": "BL-029",
          "rule_name": "Bill of Lading Not Applicable for Air Shipments",
          "rule_layer": "Business",
          "dq_dimension": "Consistency",
          "rule_type": "Conditional",
          "rule_description": "Air shipments use Air Waybill (AWB), not Bill of Lading. bill_of_lading_no should be null or flagged if populated for AIR transport mode.",
          "rule_expression": "IF transport_mode = ''AIR'' THEN bill_of_lading_no IS NULL",
          "severity": "Medium",
          "expected_behavior": "Air shipments do not have a bill_of_lading_no.",
          "failure_example": "transport_mode = ''AIR'', bill_of_lading_no = ''MAEU123456789''.",
          "pass_example": "transport_mode = ''AIR'', bill_of_lading_no = NULL, awb_no = ''176-12345678''.",
          "remediation": "Mutually exclusive validation: only one of bill_of_lading_no or awb_no should be populated per transport mode."
        }
      ]
    },
    {
      "field_name": "awb_no",
      "inferred_data_type": "String (IATA AWB format: XXX-XXXXXXXX)",
      "business_context": "Air Waybill number — the transport contract for air freight. Required by Saudi Customs and GAACA for air cargo clearance.",
      "rules": [
        {
          "rule_id": "BL-030",
          "rule_name": "AWB Required for Air Freight Shipments at Clearance",
          "rule_layer": "Business",
          "dq_dimension": "Completeness",
          "rule_type": "Conditional",
          "rule_description": "For transport_mode = ''AIR'', awb_no must be populated before customs clearance. It follows IATA format: 3-digit airline prefix + 8-digit serial (e.g., 176-12345678).",
          "rule_expression": "IF transport_mode = ''AIR'' AND shipment_status IN (''ARRIVED'',''UNDER_CUSTOMS_CLEARANCE'',''CLEARED'') THEN awb_no IS NOT NULL AND awb_no REGEXP ''^[0-9]{3}-[0-9]{8}$''",
          "severity": "Critical",
          "expected_behavior": "Air shipments have a valid IATA-format AWB number before clearance.",
          "failure_example": "transport_mode = ''AIR'', awb_no = NULL or ''AWB123''.",
          "pass_example": "transport_mode = ''AIR'', awb_no = ''176-12345678''.",
          "remediation": "Add IATA format validation; require AWB before customs clearance workflow step."
        },
        {
          "rule_id": "BL-031",
          "rule_name": "AWB Not Applicable for Sea Shipments",
          "rule_layer": "Business",
          "dq_dimension": "Consistency",
          "rule_type": "Conditional",
          "rule_description": "Sea shipments should not have an AWB number populated. Presence of awb_no for SEA transport mode indicates a data entry error.",
          "rule_expression": "IF transport_mode = ''SEA'' THEN awb_no IS NULL",
          "severity": "Medium",
          "expected_behavior": "Sea shipments have null AWB.",
          "failure_example": "transport_mode = ''SEA'', awb_no = ''176-12345678''.",
          "pass_example": "transport_mode = ''SEA'', awb_no = NULL, bill_of_lading_no = ''MAEU123456789''.",
          "remediation": "Mutual exclusivity rule: AWB for AIR, B/L for SEA."
        }
      ]
    },
    {
      "field_name": "container_no",
      "inferred_data_type": "String (ISO 6346 format: AAAA-999999-D)",
      "business_context": "ISO container identification number for containerized sea freight. Tracked by Saudi Customs and port authorities for manifest matching.",
      "rules": [
        {
          "rule_id": "BL-032",
          "rule_name": "Container Number Required for Containerized Sea Freight",
          "rule_layer": "Business",
          "dq_dimension": "Completeness",
          "rule_type": "Conditional",
          "rule_description": "When transport_mode = ''SEA'' and container_type is not ''BULK'' or ''BREAKBULK'', container_no must be populated.",
          "rule_expression": "IF transport_mode = ''SEA'' AND container_type NOT IN (''BULK'',''BREAKBULK'',''RO-RO'') AND shipment_status NOT IN (''DRAFT'',''CONFIRMED'') THEN container_no IS NOT NULL",
          "severity": "High",
          "expected_behavior": "Containerized sea shipments have a container number.",
          "failure_example": "transport_mode = ''SEA'', container_type = ''20GP'', container_no = NULL.",
          "pass_example": "container_no = ''MAEU1234567''.",
          "remediation": "Require container_no at booking for containerized cargo."
        },
        {
          "rule_id": "BL-033",
          "rule_name": "Container Number Must Follow ISO 6346 Format",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Conditional",
          "rule_description": "container_no must follow ISO 6346 format: 4 uppercase alpha owner code + 6 digits + 1 check digit (e.g., MAEU1234567).",
          "rule_expression": "container_no REGEXP ''^[A-Z]{4}[0-9]{7}$'' (when not null)",
          "severity": "High",
          "expected_behavior": "Valid ISO 6346 container number format.",
          "failure_example": "container_no = ''CONTAINER-123'' or ''MAEU123456''.",
          "pass_example": "container_no = ''MAEU1234567''.",
          "remediation": "Apply regex validation at data entry; checksum digit validation for high-value shipments."
        }
      ]
    },
    {
      "field_name": "container_type",
      "inferred_data_type": "String/Enum",
      "business_context": "Type of container (20GP, 40GP, 40HC, Reefer, etc.). Affects port handling charges, customs inspection procedures, and storage calculations.",
      "rules": [
        {
          "rule_id": "BL-034",
          "rule_name": "Container Type Must Be From ISO Standard List",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Referential",
          "rule_description": "container_type must be from the ISO container type reference list used by Saudi Customs and major shipping lines.",
          "rule_expression": "container_type IN (''20GP'',''40GP'',''40HC'',''20RF'',''40RF'',''20OT'',''40OT'',''20FR'',''40FR'',''45HC'',''BULK'',''BREAKBULK'',''RO-RO'',''LCL'') OR container_type IS NULL",
          "severity": "High",
          "expected_behavior": "Only recognized container type codes used.",
          "failure_example": "container_type = ''Standard 40ft''.",
          "pass_example": "container_type = ''40HC''.",
          "remediation": "Provide dropdown with ISO container types; maintain ref_container_types table."
        }
      ]
    },
    {
      "field_name": "seal_no",
      "inferred_data_type": "String",
      "business_context": "Customs or carrier seal number applied to the container. Verified by Saudi Customs at port of entry. Broken or mismatched seals trigger physical inspection.",
      "rules": [
        {
          "rule_id": "BL-035",
          "rule_name": "Seal Number Required for FCL Container Shipments at Customs",
          "rule_layer": "Business",
          "dq_dimension": "Completeness",
          "rule_type": "Conditional",
          "rule_description": "For full container load (FCL) sea shipments reaching customs clearance, seal_no must be populated to verify container integrity.",
          "rule_expression": "IF transport_mode = ''SEA'' AND container_type IN (''20GP'',''40GP'',''40HC'',''20RF'',''40RF'',''45HC'') AND shipment_status = ''UNDER_CUSTOMS_CLEARANCE'' THEN seal_no IS NOT NULL",
          "severity": "High",
          "expected_behavior": "FCL sea shipments at customs have a seal number.",
          "failure_example": "FCL sea shipment at customs clearance with seal_no = NULL.",
          "pass_example": "seal_no = ''CN123456789''.",
          "remediation": "Require seal_no data entry at cargo receipt or loading confirmation stage."
        }
      ]
    },
    {
      "field_name": "gross_weight_kg",
      "inferred_data_type": "Decimal/Numeric",
      "business_context": "Total gross weight including packaging and container. Used by Saudi Customs for duty calculation basis, freight billing, and port handling charges.",
      "rules": [
        {
          "rule_id": "BL-036",
          "rule_name": "Gross Weight Must Be Positive and Non-Zero",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Conditional",
          "rule_description": "gross_weight_kg must be greater than 0 for any non-DRAFT shipment. A zero or negative weight is physically impossible.",
          "rule_expression": "IF shipment_status != ''DRAFT'' THEN gross_weight_kg IS NOT NULL AND gross_weight_kg > 0",
          "severity": "Critical",
          "expected_behavior": "All active shipments have a positive gross weight.",
          "failure_example": "gross_weight_kg = 0 or -50 or NULL for a CLEARED shipment.",
          "pass_example": "gross_weight_kg = 25000.50.",
          "remediation": "Add NOT NULL and CHECK (gross_weight_kg > 0) constraint at DDL level."
        },
        {
          "rule_id": "BL-037",
          "rule_name": "Gross Weight Plausibility Check by Transport Mode",
          "rule_layer": "Business",
          "dq_dimension": "Accuracy",
          "rule_type": "Conditional",
          "rule_description": "Gross weight should be within plausible ranges per transport mode: AIR < 150,000 kg (IATA max per flight); SEA < 70,000,000 kg (max vessel capacity).",
