          "rule_description": "incoterm_code must be one of the 11 Incoterms 2020 codes as published by the International Chamber of Commerce.",
          "rule_expression": "incoterm_code IN (''EXW'', ''FCA'', ''CPT'', ''CIP'', ''DAP'', ''DPU'', ''DDP'', ''FAS'', ''FOB'', ''CFR'', ''CIF'')",
