          "rule_expression": "container_type IN (''20GP'', ''40GP'', ''40HC'', ''45HC'', ''20RF'', ''40RF'', ''20OT'', ''40OT'', ''20FR'', ''40FR'', ''LCL'', ''BULK'', ''TANKER'')",
          "severity": "High",
