          "rule_expression": "IF freight_currency != ''SAR'' THEN freight_amount_sar = freight_amount * (SELECT exchange_rate FROM sama_fx_rates WHERE currency = freight_currency AND rate_date = shipment_date)",
          "severity": "Critical",
          "expected_behavior": "USD freight converted to SAR at SAMA rate: USD 10,000 × 3.75 = SAR 37,500.",
          "failure_example": "freight_currency = ''USD'', no SAR equivalent stored or applied to invoice.",
