      "business_context": "ISO country code of the shipment''s origin. Used in customs declarations, preferential trade agreements, and ZATCA duty rate determination.",
      "rules": [
        {
          "rule_id": "BL-012",
          "rule_name": "Origin Country Code Must Be Valid ISO 3166-1",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Referential",
          "rule_description": "origin_country_code must be a valid ISO 3166-1 alpha-2 or alpha-3 country code from the reference table.",
          "rule_expression": "origin_country_code IN (SELECT country_code FROM ref_iso_countries)",
          "severity": "Critical",
          "expected_behavior": "origin_country_code = ''SA'' or ''SAU''",
          "failure_example": "origin_country_code = ''XX'' or ''KSA''",
          "pass_example": "origin_country_code = ''SA''",
          "remediation": "Validate against ISO 3166-1 reference table. Replace free-text input with country lookup dropdown."
        },
        {
          "rule_id": "BL-013",
          "rule_name": "Origin Country Must Not Be Same as Destination Country",
          "rule_layer": "Business",
          "dq_dimension": "Consistency",
          "rule_type": "Cross-Field",
          "rule_description": "For IMPORT and EXPORT shipments, the origin country code must differ from the destination country code. Identical values indicate a data entry error.",
          "rule_expression": "IF shipment_type IN (''IMPORT'',''EXPORT'') THEN origin_country_code != destination_country_code",
          "severity": "High",
          "expected_behavior": "origin_country_code = ''SA'', destination_country_code = ''AE''",
          "failure_example": "origin_country_code = ''SA'', destination_country_code = ''SA'' for an EXPORT shipment.",
          "pass_example": "origin_country_code = ''SA'', destination_country_code = ''AE''",
          "remediation": "Add cross-field validation rule. Alert operator when both country codes are identical for import/export types."
        }
      ]
    },
    {
      "field_name": "destination_country_code",
      "inferred_data_type": "VARCHAR(3)",
      "business_context": "ISO country code of the shipment destination. Used for export control, duty determination, trade sanctions screening, and ZATCA regulatory reporting.",
      "rules": [
        {
          "rule_id": "BL-014",
          "rule_name": "Destination Country Code Must Be Valid ISO 3166-1",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Referential",
          "rule_description": "destination_country_code must be a valid ISO 3166-1 alpha-2 or alpha-3 country code from the reference table.",
          "rule_expression": "destination_country_code IN (SELECT country_code FROM ref_iso_countries)",
          "severity": "Critical",
          "expected_behavior": "destination_country_code = ''AE'' or ''ARE''",
          "failure_example": "destination_country_code = ''EU'' or ''GULF''",
          "pass_example": "destination_country_code = ''AE''",
          "remediation": "Validate against ISO 3166-1 reference table. Use controlled country selector in UI."
        },
        {
          "rule_id": "BL-015",
          "rule_name": "Destination Country Must Be Screened for Sanctions",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Referential",
          "rule_description": "destination_country_code must be checked against active trade sanctions and embargo lists maintained by Saudi authorities and international bodies. Shipments to sanctioned countries require special regulatory approval.",
          "rule_expression": "destination_country_code NOT IN (SELECT country_code FROM ref_sanctioned_countries) OR special_approval_flag = TRUE",
          "severity": "Critical",
          "expected_behavior": "Destination country is not on the active sanctions list.",
          "failure_example": "destination_country_code maps to a sanctioned country with no approval flag.",
          "pass_example": "destination_country_code = ''AE'' — not on sanctions list.",
          "remediation": "Integrate sanctions screening API or maintain a regularly updated sanctions reference table. Block submission if country is sanctioned without approval."
        }
      ]
    },
    {
      "field_name": "port_of_loading",
      "inferred_data_type": "VARCHAR(100)",
      "business_context": "The port or airport where the shipment is loaded onto the carrier. Required in Bills of Lading and customs export declarations.",
      "rules": [
        {
          "rule_id": "BL-016",
          "rule_name": "Port of Loading Must Be Valid UN/LOCODE",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Referential",
          "rule_description": "port_of_loading should reference a valid UN/LOCODE from the port reference table to ensure standardization across systems and customs reporting.",
          "rule_expression": "port_of_loading IN (SELECT locode FROM ref_ports) OR port_of_loading IS NOT NULL",
          "severity": "High",
          "expected_behavior": "port_of_loading = ''SAJED'' (Jeddah Islamic Port UN/LOCODE)",
          "failure_example": "port_of_loading = ''Jeddah Port'' (free text, non-standardized)",
          "pass_example": "port_of_loading = ''SAJED''",
          "remediation": "Implement port lookup reference table with UN/LOCODE values. Replace free-text with standardized code."
        },
        {
          "rule_id": "BL-017",
          "rule_name": "Port of Loading Must Be Consistent with Origin Country",
          "rule_layer": "Business",
          "dq_dimension": "Consistency",
          "rule_type": "Cross-Field",
          "rule_description": "For EXPORT shipments, the port_of_loading must be located in the origin_country_code country.",
          "rule_expression": "IF shipment_type = ''EXPORT'' THEN ref_ports.country_code WHERE port_code = port_of_loading = origin_country_code",
          "severity": "High",
          "expected_behavior": "EXPORT shipment: origin_country_code = ''SA'', port_of_loading = ''SAJED''",
          "failure_example": "EXPORT shipment: origin_country_code = ''SA'', port_of_loading = ''AEJEA'' (Dubai port)",
          "pass_example": "EXPORT: origin = ''SA'', port_of_loading = ''SAJED''",
          "remediation": "Cross-validate port country against origin country code using port reference table."
        }
      ]
    },
    {
      "field_name": "port_of_discharge",
      "inferred_data_type": "VARCHAR(100)",
      "business_context": "The port or airport where the shipment is discharged from the carrier. Required in customs import declarations and freight documentation.",
      "rules": [
        {
          "rule_id": "BL-018",
          "rule_name": "Port of Discharge Must Be Valid UN/LOCODE",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Referential",
          "rule_description": "port_of_discharge should reference a valid UN/LOCODE from the port reference table.",
          "rule_expression": "port_of_discharge IN (SELECT locode FROM ref_ports)",
          "severity": "High",
          "expected_behavior": "port_of_discharge = ''AEJEA'' (Jebel Ali Port)",
          "failure_example": "port_of_discharge = ''Dubai Port'' (free text)",
          "pass_example": "port_of_discharge = ''AEJEA''",
          "remediation": "Implement port reference table. Replace free-text with standardized UN/LOCODE."
        },
        {
          "rule_id": "BL-019",
          "rule_name": "Port of Discharge Must Differ from Port of Loading",
          "rule_layer": "Business",
          "dq_dimension": "Consistency",
          "rule_type": "Cross-Field",
          "rule_description": "port_of_discharge must be different from port_of_loading. A shipment cannot be loaded and discharged at the same port.",
          "rule_expression": "port_of_discharge != port_of_loading",
          "severity": "High",
          "expected_behavior": "port_of_loading = ''SAJED'', port_of_discharge = ''AEJEA''",
          "failure_example": "port_of_loading = ''SAJED'', port_of_discharge = ''SAJED''",
          "pass_example": "port_of_loading = ''SAJED'', port_of_discharge = ''AEJEA''",
          "remediation": "Add cross-field validation to reject records where both port codes are identical."
        }
      ]
    },
    {
      "field_name": "final_destination",
      "inferred_data_type": "VARCHAR(200)",
      "business_context": "The ultimate delivery location of the goods beyond the port of discharge. May contain a city, facility address, or warehouse location.",
      "rules": [
        {
          "rule_id": "BL-020",
          "rule_name": "Final Destination Must Be Populated for DAP and DDP Incoterms",
          "rule_layer": "Business",
          "dq_dimension": "Completeness",
          "rule_type": "Conditional",
          "rule_description": "When incoterm_code is DAP, DPU, or DDP, the final_destination must be populated because the seller is responsible for delivery to a named place.",
          "rule_expression": "IF incoterm_code IN (''DAP'',''DPU'',''DDP'') THEN final_destination IS NOT NULL AND TRIM(final_destination) != ''''",
          "severity": "Critical",
          "expected_behavior": "DAP shipment has a populated final_destination.",
          "failure_example": "incoterm_code = ''DDP'', final_destination = NULL",
          "pass_example": "incoterm_code = ''DAP'', final_destination = ''Dubai Logistics City, UAE''",
          "remediation": "Add conditional validation that enforces final_destination when seller-responsible Incoterms are used."
        }
      ]
    },
    {
      "field_name": "incoterm_code",
      "inferred_data_type": "VARCHAR(3)",
      "business_context": "Incoterms 2020 code defining cost, risk, and delivery responsibility between buyer and seller. Affects duty calculation, insurance requirements, and ZATCA customs valuation.",
      "rules": [
        {
          "rule_id": "BL-021",
          "rule_name": "Incoterm Code Must Be Valid Incoterms 2020 Value",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Referential",
          "rule_description": "incoterm_code must be one of the 11 official Incoterms 2020 codes published by the International Chamber of Commerce.",
          "rule_expression": "incoterm_code IN (''EXW'',''FCA'',''CPT'',''CIP'',''DAP'',''DPU'',''DDP'',''FAS'',''FOB'',''CFR'',''CIF'')",
          "severity": "Critical",
          "expected_behavior": "incoterm_code = ''CIF''",
          "failure_example": "incoterm_code = ''DDU'' (Incoterms 2010, deprecated) or ''FREE''",
          "pass_example": "incoterm_code = ''FOB''",
          "remediation": "Maintain Incoterms 2020 reference table. Reject deprecated terms and provide migration mapping for legacy values."
        },
        {
          "rule_id": "BL-022",
          "rule_name": "Sea-Only Incoterms Must Not Be Used for Air or Road Transport",
          "rule_layer": "Business",
          "dq_dimension": "Consistency",
          "rule_type": "Cross-Field",
          "rule_description": "Incoterms FAS, FOB, CFR, and CIF are exclusively applicable to sea and inland waterway transport. They must not be used when transport_mode is AIR or ROAD.",
          "rule_expression": "IF incoterm_code IN (''FAS'',''FOB'',''CFR'',''CIF'') THEN transport_mode IN (''SEA'',''INLAND WATERWAY'')",
          "severity": "High",
          "expected_behavior": "FOB incoterm is used with SEA transport mode.",
          "failure_example": "incoterm_code = ''FOB'', transport_mode = ''AIR''",
          "pass_example": "incoterm_code = ''FOB'', transport_mode = ''SEA''",
          "remediation": "Add cross-field validation between incoterm_code and transport_mode. Warn or block invalid combinations."
        }
      ]
    },
    {
      "field_name": "transport_mode",
      "inferred_data_type": "VARCHAR(20)",
      "business_context": "Primary mode of transportation for the shipment. Determines required document types (B/L vs AWB), applicable Incoterms, and customs declaration format.",
      "rules": [
        {
          "rule_id": "BL-023",
          "rule_name": "Transport Mode Must Be from Approved List",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Referential",
          "rule_description": "transport_mode must be one of the approved transport classification values: SEA, AIR, ROAD, RAIL, MULTIMODAL.",
          "rule_expression": "transport_mode IN (''SEA'',''AIR'',''ROAD'',''RAIL'',''MULTIMODAL'')",
          "severity": "Critical",
          "expected_behavior": "transport_mode = ''SEA''",
          "failure_example": "transport_mode = ''ship'' or ''ocean''",
          "pass_example": "transport_mode = ''AIR''",
          "remediation": "Implement reference table. Use controlled dropdown in UI. Reject non-standard values."
        },
        {
          "rule_id": "BL-024",
          "rule_name": "Bill of Lading Required for Sea Transport",
          "rule_layer": "Business",
          "dq_dimension": "Completeness",
          "rule_type": "Conditional",
          "rule_description": "When transport_mode = ''SEA'', bill_of_lading_no must be populated. A sea shipment cannot be processed without a Bill of Lading reference.",
          "rule_expression": "IF transport_mode = ''SEA'' THEN bill_of_lading_no IS NOT NULL AND TRIM(bill_of_lading_no) != ''''",
          "severity": "Critical",
          "expected_behavior": "Sea shipment has a valid bill_of_lading_no.",
          "failure_example": "transport_mode = ''SEA'', bill_of_lading_no = NULL",
          "pass_example": "transport_mode = ''SEA'', bill_of_lading_no = ''MEDUB1234567''",
          "remediation": "Enforce conditional mandatory rule at submission stage for sea shipments."
        },
        {
          "rule_id": "BL-025",
          "rule_name": "AWB Required for Air Transport",
          "rule_layer": "Business",
          "dq_dimension": "Completeness",
          "rule_type": "Conditional",
          "rule_description": "When transport_mode = ''AIR'', awb_no must be populated. Air shipments require a valid Air Waybill number for tracking and customs clearance.",
          "rule_expression": "IF transport_mode = ''AIR'' THEN awb_no IS NOT NULL AND TRIM(awb_no) != ''''",
          "severity": "Critical",
          "expected_behavior": "Air shipment has a valid awb_no.",
          "failure_example": "transport_mode = ''AIR'', awb_no = NULL",
          "pass_example": "transport_mode = ''AIR'', awb_no = ''176-12345678''",
          "remediation": "Enforce conditional mandatory rule at submission stage for air shipments."
        }
      ]
    },
    {
      "field_name": "carrier_name",
      "inferred_data_type": "VARCHAR(150)",
      "business_context": "Legal name of the shipping company or airline responsible for transporting the shipment.",
      "rules": [
        {
          "rule_id": "BL-026",
          "rule_name": "Carrier Name Must Not Be Null for Submitted Shipments",
          "rule_layer": "Business",
          "dq_dimension": "Completeness",
          "rule_type": "Conditional",
          "rule_description": "carrier_name is mandatory for all shipments with status SUBMITTED or beyond. A shipment cannot be submitted without identifying the responsible carrier.",
          "rule_expression": "IF shipment_status NOT IN (''DRAFT'',''CANCELLED'') THEN carrier_name IS NOT NULL AND TRIM(carrier_name) != ''''",
          "severity": "High",
          "expected_behavior": "Submitted shipment has a populated carrier_name.",
          "failure_example": "shipment_status = ''SUBMITTED'', carrier_name = NULL",
          "pass_example": "carrier_name = ''Saudi Shipping Company''",
          "remediation": "Add NOT NULL validation at status transition from DRAFT to SUBMITTED."
        },
        {
          "rule_id": "BL-027",
          "rule_name": "Carrier Name Must Be Validated Against Approved Carrier Registry",
          "rule_layer": "Business",
          "dq_dimension": "Accuracy",
          "rule_type": "Referential",
          "rule_description": "carrier_name should be validated against the approved carrier registry to ensure the carrier is licensed and authorized to operate on the declared trade route.",
          "rule_expression": "carrier_name IN (SELECT carrier_name FROM ref_approved_carriers)",
          "severity": "Medium",
          "expected_behavior": "Carrier is listed in the approved registry.",
          "failure_example": "carrier_name = ''Unknown Logistics Co.'' not found in registry.",
          "pass_example": "carrier_name = ''Saudi Shipping Company'' found in registry.",
          "remediation": "Maintain and regularly update an approved carrier reference table. Add lookup validation with a warning flag for unregistered carriers."
        }
      ]
    },
    {
      "field_name": "vessel_flight_no",
      "inferred_data_type": "VARCHAR(50)",
      "business_context": "Identifier of the vessel or flight used for the shipment. Required for cargo tracking and customs pre-arrival processing.",
      "rules": [
        {
          "rule_id": "BL-028",
          "rule_name": "Vessel or Flight Number Must Be Populated for Non-Road Transport",
          "rule_layer": "Business",
          "dq_dimension": "Completeness",
          "rule_type": "Conditional",
          "rule_description": "vessel_flight_no is required when transport_mode is SEA or AIR. Road shipments may use a vehicle registration number in this field.",
          "rule_expression": "IF transport_mode IN (''SEA'',''AIR'') THEN vessel_flight_no IS NOT NULL AND TRIM(vessel_flight_no) != ''''",
          "severity": "High",
          "expected_behavior": "Sea or Air shipment has a vessel or flight number.",
          "failure_example": "transport_mode = ''AIR'', vessel_flight_no = NULL",
          "pass_example": "transport_mode = ''AIR'', vessel_flight_no = ''SV723''",
          "remediation": "Enforce conditional mandatory rule. Add format validation based on transport mode."
        }
      ]
    },
    {
      "field_name": "bill_of_lading_no",
      "inferred_data_type": "VARCHAR(50)",
      "business_context": "Unique reference of the Bill of Lading — a legally binding document for sea freight that serves as receipt, contract of carriage, and document of title.",
      "rules": [
        {
          "rule_id": "BL-029",
          "rule_name": "Bill of Lading Number Must Be Unique Across Sea Shipments",
          "rule_layer": "Business",
          "dq_dimension": "Uniqueness",
          "rule_type": "Conditional",
          "rule_description": "bill_of_lading_no must be unique for SEA shipments. Duplicate B/L numbers could result in duplicate customs declarations and legal disputes.",
          "rule_expression": "IF transport_mode = ''SEA'' THEN COUNT(bill_of_lading_no) = COUNT(DISTINCT bill_of_lading_no) WHERE bill_of_lading_no IS NOT NULL",
          "severity": "Critical",
          "expected_behavior": "Each B/L number appears only once across sea shipments.",
          "failure_example": "Two sea shipments share bill_of_lading_no = ''MEDUB1234567''.",
          "pass_example": "bill_of_lading_no = ''MEDUB1234567'' appears once.",
          "remediation": "Add unique constraint on bill_of_lading_no filtered to SEA transport mode records."
        },
        {
          "rule_id": "BL-030",
          "rule_name": "Bill of Lading Must Not Be Populated for Air Shipments",
          "rule_layer": "Business",
          "dq_dimension": "Consistency",
          "rule_type": "Conditional",
          "rule_description": "Air shipments use AWB, not Bill of Lading. Populating bill_of_lading_no for air shipments indicates a data entry error.",
          "rule_expression": "IF transport_mode = ''AIR'' THEN bill_of_lading_no IS NULL",
          "severity": "Medium",
          "expected_behavior": "Air shipment has no bill_of_lading_no.",
          "failure_example": "transport_mode = ''AIR'', bill_of_lading_no = ''MEDUB1234567''",
          "pass_example": "transport_mode = ''AIR'', bill_of_lading_no = NULL, awb_no = ''176-12345678''",
          "remediation": "Add mutual exclusivity validation between bill_of_lading_no and awb_no based on transport_mode."
        }
      ]
    },
    {
      "field_name": "awb_no",
      "inferred_data_type": "VARCHAR(20)",
      "business_context": "Air Waybill number — the IATA-standard transport document identifier for air freight shipments.",
      "rules": [
        {
          "rule_id": "BL-031",
          "rule_name": "AWB Number Must Follow IATA Format",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Conditional",
          "rule_description": "awb_no must follow the IATA standard format: 3-digit airline prefix + hyphen + 8-digit serial number (e.g., 176-12345678).",
          "rule_expression": "IF awb_no IS NOT NULL THEN REGEXP_LIKE(awb_no, ''^[0-9]{3}-[0-9]{8}$'')",
          "severity": "High",
          "expected_behavior": "awb_no = ''176-12345678''",
          "failure_example": "awb_no = ''AWB123456'' or ''17612345678''",
          "pass_example": "awb_no = ''176-12345678''",
          "remediation": "Add IATA AWB format regex validation at data entry. Provide format guide to operators."
        },
        {
          "rule_id": "BL-032",
          "rule_name": "AWB Must Not Be Populated for Sea Shipments",
          "rule_layer": "Business",
          "dq_dimension": "Consistency",
          "rule_type": "Conditional",
          "rule_description": "Sea shipments use Bill of Lading, not AWB. Populating awb_no for sea shipments indicates a data entry error.",
          "rule_expression": "IF transport_mode = ''SEA'' THEN awb_no IS NULL",
          "severity": "Medium",
          "expected_behavior": "Sea shipment has no awb_no.",
          "failure_example": "transport_mode = ''SEA'', awb_no = ''176-12345678''",
          "pass_example": "transport_mode = ''SEA'', awb_no = NULL, bill_of_lading_no = ''MEDUB1234567''",
          "remediation": "Enforce mutual exclusivity: if transport_mode = SEA, clear awb_no. If transport_mode = AIR, clear bill_of_lading_no."
        }
      ]
    },
    {
      "field_name": "container_no",
      "inferred_data_type": "VARCHAR(15)",
      "business_context": "ISO 6346 container identifier used for tracking, customs inspection, and port operations.",
      "rules": [
        {
          "rule_id": "BL-033",
          "rule_name": "Container Number Must Follow ISO 6346 Format",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Conditional",
          "rule_description": "container_no must follow the ISO 6346 standard: 4 uppercase letters (owner code + equipment category) followed by 7 digits.",
          "rule_expression": "IF container_no IS NOT NULL THEN REGEXP_LIKE(container_no, ''^[A-Z]{4}[0-9]{7}$'')",
          "severity": "High",
          "expected_behavior": "container_no = ''MSCU1234567''",
          "failure_example": "container_no = ''CONT123'' or ''MSC-1234567''",
          "pass_example": "container_no = ''MSCU1234567''",
          "remediation": "Add ISO 6346 regex validation at data entry. Provide container number format reference to operators."
        },
        {
          "rule_id": "BL-034",
          "rule_name": "Container Number Required for Sea Shipments",
          "rule_layer": "Business",
          "dq_dimension": "Completeness",
          "rule_type": "Conditional",
          "rule_description": "For SEA transport shipments that are containerized, container_no must be provided. It is mandatory for customs tracking and port operations.",
          "rule_expression": "IF transport_mode = ''SEA'' AND container_type IS NOT NULL THEN container_no IS NOT NULL",
          "severity": "High",
