          "failure_example": "transport_mode = ''SEA'', container_type = ''40HC'', container_no = NULL",
          "pass_example": "transport_mode = ''SEA'', container_type = ''40HC'', container_no = ''MSCU1234567''",
          "remediation": "Add conditional mandatory rule: if transport_mode = SEA and container_type is populated, require container_no."
        }
      ]
    },
    {
      "field_name": "container_type",
      "inferred_data_type": "VARCHAR(10)",
      "business_context": "Standardized classification of the container type and size used in the shipment.",
      "rules": [
        {
          "rule_id": "BL-035",
          "rule_name": "Container Type Must Be from Approved List",
          "rule_layer": "Business",
          "dq_dimension": "Validity",
          "rule_type": "Referential",
          "rule_description": "container_type must be a recognized ISO container type code: 20GP, 40GP, 40HC, 20RF, 40RF, 20OT, 40OT, 20FR, 40FR.",
          "rule_expression": "container_type IN (''20GP'',''40GP'',''40HC'',''20RF'',''40RF'',''20OT'',''40OT'',''20FR'',''40FR'') OR container_type IS NULL",
          "severity": "Medium",
          "expected_behavior": "container_type = ''40HC''",
          "failure_example": "container_type = ''Large'' or ''40-foot''",
          "pass_example": "container_type = ''40GP''",
          "remediation": "Implement container type reference table. Replace free-text with controlled dropdown."
        },
        {
          "rule_id": "BL-036",
          "rule_name": "Container Type Must Only Be Populated for Sea Shipments",
          "rule_layer": "Business",
          "dq_dimension": "Consistency",
          "rule_type": "Conditional",
          "rule_description": "container_type is only applicable to sea freight. It must be null for AIR or ROAD-only shipments unless multimodal.",
          "rule_expression": "IF transport_mode NOT IN (''SEA'',''MULTIMODAL'') THEN container_type IS NULL",
          "severity": "Low",
          "expected_behavior": "Air shipment has container_type = NULL.",
          "failure_example": "transport_mode = ''AIR'', container_type = ''40GP''",
          "pass_example": "transport_mode = ''AIR'', container_type = NULL",
          "remediation": "Add conditional rule: clear container_type for non-sea shipments."
        }
      ]
    },
    {
      "field_name": "seal_no",
      "inferred_data_type": "VARCHAR(50)",
      "business_context": "Security seal identifier applied to container after loading. Used by customs for tamper verification and inspection scheduling.",
      "rules": [
        {
          "rule_id": "BL-037",
          "rule_name": "Seal Number Required When Container Number Is Populated",
          "rule_layer": "Business",
          "dq_dimension": "Completeness",
          "rule_type": "Conditional",
          "rule_description": "When container_no is provided, seal_no must also be provided. A container without a recorded seal number fails customs integrity requirements.",
          "rule_expression": "IF container_no IS NOT NULL THEN seal_no IS NOT NULL AND TRIM(seal_no) != ''''",
